window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["artifacts"]={"updatedAt":"2026-06-24","count":242,"artifacts":[{"id":"lenh-bai-pham-linh-cac","name":"Lệnh bài Phẩm Linh Các","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm","Trương Hướng Phàm"],"trangThai":"dang-co","blurb":"Lệnh bài dùng để lấy tiên ngọc tại Phẩm Linh Các; ấn vào trận pháp phát ánh sáng tím, mở cửa truyền tống và xác nhận thân phận lĩnh tiên ngọc.","detail":"Lệnh bài Phẩm Linh Các được ấn vào chỗ ba đạo bạch ngân giao nhau để kích hoạt trận pháp và phát ánh sáng tím, mở cánh cửa truyền tống lên tầng thứ bảy. Khi đưa vào thân nhân ảnh khổng lồ trong tiên cảnh, lệnh bài xác nhận chủ nhân là Đệ thất tử Tử hệ và cho phép lĩnh tiên ngọc; sau khi xong việc lệnh bài ngưng tụ trở lại và đẩy người dùng ra khỏi tầng bảy.","nguon":["@c0458"]},{"id":"chien-xa-vang-kim-ma-tu","name":"Chiến xa vàng của Kim Ma tử","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo di chuyển cấp tôn giả","soHuu":["Kim Ma tử"],"trangThai":"dang-co","blurb":"Chiến xa khổng lồ màu vàng cao hơn ngàn trượng, đầy mũi nhọn, do bốn yêu thú khổng lồ nâng đỡ phi hành.","detail":"Toàn thân vàng kim, kết cấu chi chít những mũi nhọn kinh khủng. Bốn yêu thú khổng lồ nâng đỡ chiến xa phi hành giữa hư không. Trên xe có ghế lớn dành cho Kim Ma tử nằm, vây quanh là mười tùy tùng trường sam bạc mặt vô cảm mắt âm hàn.","nguon":["@c0460"]},{"id":"ngoc-boi-noan-ngoc-trieu-tinh-sat","name":"Ngọc bội noãn ngọc (Triệu Tinh Sát)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Vật phẩm tùy thân","soHuu":["Triệu Tinh Sát"],"trangThai":"dang-co","blurb":"Ngọc bội bằng noãn ngọc Triệu Tinh Sát đeo bên hông.","detail":"Ngọc bội tinh tế bằng noãn ngọc đeo bên hông, tôn lên dáng vẻ nho nhã ôn hòa của đại sư huynh Tử hệ.","nguon":["@c0460"]},{"id":"co-kiem-trieu-tinh-sat","name":"Cổ kiếm (Triệu Tinh Sát)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Triệu Tinh Sát"],"trangThai":"dang-co","blurb":"Thanh cổ kiếm Triệu Tinh Sát đeo sau lưng.","detail":"Cổ kiếm đeo chéo sau lưng, vũ khí bản mệnh mà đại sư huynh Tử hệ Thiên Vận Tông mang theo khi canh giữ tử vụ đại trận và nghênh đón khách.","nguon":["@c0460"]},{"id":"hon-thu-xa-than-xa","name":"Hồn Thú (chẳng khuất phục thiên địa tiên ma)","cn":"","category":"khac","categoryLabel":"Linh thú chiến đấu","phamCap":"Linh thú mạnh chứa trong Xạ Thần Xa","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Linh thú chẳng khuất phục thiên địa tiên ma, ẩn trong Xạ Thần Xa của Vương Lâm.","detail":"Vương Lâm triệu Hồn Thú từ Xạ Thần Xa, hóa thành sao băng đâm xuyên vào cơ thể cổ yêu. Bị cổ yêu lôi ra định nuốt nhưng được tiếng hét của Xích Liệt cứu; sau đó Hồn Thú không giãy giụa mà trừng mắt nhìn Triệu Tinh Sát rồi tự trở về Khu Thú Quyển / Xạ Thần Xa.","nguon":["@c0463"]},{"id":"ngoc-gian-cam-phap-tu-su-ty","name":"Ngọc giản hai cấm pháp (tứ sư tỷ trao)","cn":"","category":"phap-bao","categoryLabel":"Vật ghi chép","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản tứ sư tỷ trao cho Vương Lâm, ghi đại na di và Cửu Chuyển Luyện Tiên Quyết.","detail":"Ngọc giản chứa hai đạo cấm pháp: thuật Đại Na Di dịch chuyển mười vạn dặm và một cấm pháp do sư tôn Thiên Vận Tử phỏng theo hạ phẩm tiên thuật sáng tạo (được Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết, uy lực rất lớn). Tứ sư tỷ trao đêm khuya yến tàn, coi như xin lỗi việc tháng trước — lúc đó nàng dùng cấm pháp phong ấn nhưng chưa thực sự ra tay.","nguon":["@c0464"]},{"id":"tien-ha-noan-ngoc","name":"Tiên hà noãn ngọc","cn":"","category":"khac","categoryLabel":"Trang sức","phamCap":"","soHuu":["Đệ tử Xích Tông"],"trangThai":"dang-co","blurb":"Vật đeo bên hông đặc trưng đệ tử Xích Tông của Thiên Vận Tông.","detail":"Vật đeo bên hông bảy đệ tử Xích Tông cùng áo đỏ thêu kim long khi xuất hiện đầu tiên trong lễ giảng đạo Thiên Vận Tử kính bái tổng tông.","nguon":["@c0464"]},{"id":"phi-kiem-vang-trung-pham-tien-khi","name":"Phi kiếm màu vàng (trung phẩm tiên khí)","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm / Tiên khí","phamCap":"Trung phẩm tiên khí","soHuu":["Côn Bằng Tử"],"trangThai":"dang-co","blurb":"Phi kiếm trung phẩm tiên khí màu vàng do Tôn trưởng lão ngưng luyện vạn năm, dùng làm hậu lễ thọ yến.","detail":"Thanh phi kiếm màu vàng được Tôn trưởng lão hóa ra từ đạo kim quang phía sau, là trung phẩm tiên khí ngưng luyện vạn năm với uy năng đáng kể. Ông tặng cho Thiên Vận Tử làm hậu lễ đại thọ, đùa rằng màu vàng hợp tâm ý người thích bảy màu. Thiên Vận Tử nhận rồi ném luôn tặng lại cho Côn Bằng Tử của Hoàng Hệ, khiến hắn run rẩy xúc động tạ ơn.","nguon":["@c0465"]},{"id":"tinh-ngan-dieu","name":"Tinh Ngân điêu","cn":"","aliases":["Tử điêu"],"category":"khac","categoryLabel":"Linh thú / tài liệu pháp bảo","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Chim ba mắt cực hiếm, điểm sáng như ngọc dễ khiến người hồn xiêu phách lạc; trưởng thành biến ảo thành vạn vật và hóa hình người, là tài liệu tốt nhất để chế con rối có thần thông.","detail":"Theo truyền thừa ký ức cổ thần Đồ Ti, Tinh Ngân điêu là sinh vật kỳ dị: khi trưởng thành có thể biến ảo thành vạn vật, thậm chí hóa hình người không khác biệt, là tài liệu tốt nhất để chế con rối có thần thông. Lúc nhỏ lực công kích yếu nhưng tốc độ khó tưởng tượng, thích thôn phệ tinh thạch và tiên ngọc để trưởng thành. Người xưa lấy nội đan lúc bé luyện thành pháp bảo, khắc trận pháp thuấn di lên ngoài thì tốc độ đạt mức khó tin. Thời cổ thần nó là sủng vật tốt nhất, ưa khí tức cổ thần khi còn nhỏ nên thường tự lại gần. Con tử điêu trước mắt Vương Lâm ba mắt phát sáng như ngọc, chưa ẩn được ánh mắt nên hẳn chưa tới ngàn tuổi; nó theo khí tức cổ thần cực yếu trên người hắn mà tới, không màng tinh thạch nhưng đoạt nuốt tiên ngọc với tốc độ chỉ thấy tử quang lóe lên.","nguon":["@c0466"]},{"id":"vu-chi-de-nhi-kiem","name":"Vũ chi đệ nhị kiếm","aliases":["Xà hình bảo kiếm"],"category":"than-khi","categoryLabel":"Tiên kiếm","phamCap":"Vũ chi kiếm","soHuu":["Lăng Thiên Hầu"],"trangThai":"dang-co","blurb":"Bảo kiếm hình con rắn đầy máu tanh dưới chân Lăng Thiên Hầu; chính là Vũ chi đệ nhị kiếm hắn cướp ở Tiên giới năm xưa.","detail":"Thanh kiếm hình con rắn, thân đầy máu tanh, được tế luyện bằng phương pháp khiến người nhìn tâm thần đại chấn. Lăng Thiên Hầu đứng trên nó khi xuất hiện. Vương Lâm nhận ra đây là Vũ chi đệ nhị kiếm mà Lăng Thiên Hầu từng cướp tại Tiên giới, gợi mở ân oán/duyên nợ giữa hai người liên quan tới các thanh Vũ chi kiếm.","nguon":["@c0467"]},{"id":"bon-bong-kiem-hu-ao","name":"Bốn bóng kiếm hư ảo","category":"khac","categoryLabel":"Kiếm khí / thần thông kiếm","phamCap":"","soHuu":["Lăng Thiên Hầu"],"trangThai":"dang-co","blurb":"Bốn bóng kiếm hư ảo lơ lửng sau lưng Lăng Thiên Hầu, mỗi lần lóe lên vang một tiếng sấm.","detail":"Khi Lăng Thiên Hầu xuất hiện cùng khí tức thiên uy, sau lưng hắn hiện ra bốn bóng kiếm hư ảo; mỗi lần chúng lóe sáng lại vang lên một tiếng sấm, phô bày kiếm uy của vị Kiếm Tôn Đại La Kiếm Tông.","nguon":["@c0467"]},{"id":"xa-hinh-phi-kiem-lang-thien-hau","name":"Xà hình phi kiếm","aliases":["Xà hình kiếm tiên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Kiếm tiên","soHuu":["Lăng Thiên Hầu"],"trangThai":"dang-co","blurb":"Phi kiếm hình xà của Kiếm Tôn Lăng Thiên Hầu, bay nhanh như tia chớp.","detail":"Thanh xà hình bay nhanh như tia chớp dưới chân Lăng Thiên Hầu. Khi lao lên ngăn Thiên Vận Tử, nó bị lão chụp hư không bắt giữ làm chậm lại, kêu lên thê thiết; sau cùng được Lăng Thiên Hầu gọi về.","nguon":["@c0468"]},{"id":"ky-lan-thu-lang-thien-hau","name":"Kỳ Lân thú","aliases":["Hồng quang mi tâm"],"category":"khac","categoryLabel":"Thần thú / Pháp tướng","phamCap":"Bản mệnh thần thú","soHuu":["Lăng Thiên Hầu"],"trangThai":"dang-co","blurb":"Thần thú Kỳ Lân khổng lồ hóa từ đạo hồng quang trong mi tâm Lăng Thiên Hầu.","detail":"Một đạo quang mang màu hồng bay ra từ mi tâm Lăng Thiên Hầu, hóa thành Kỳ Lân thú khổng lồ thần võ, gầm lên lao tới đánh Thiên Vận Tử. Khi nghe tiếng gầm rít cộng hưởng phát ra từ Tôn Hồn Phiên trong nguyên thần Vương Lâm, Kỳ Lân thú dừng lại quét mắt tìm kiếm xung quanh.","nguon":["@c0468"]},{"id":"tinh-the-vang-thien-van-that-tu","name":"Tinh thể màu vàng (dấu hiệu Thiên Vận Thất tử)","category":"khac","categoryLabel":"Tín vật phong hiệu","phamCap":"không rõ","soHuu":["Côn Bằng Tử"],"trangThai":"dang-co","blurb":"Khối tinh thể màu vàng Thiên Vận Tử điểm từ mi tâm xuất ra, là dấu hiệu phong hiệu Thiên Vận Thất tử.","detail":"Thiên Vận Tử điểm tay vào mi tâm, một khối tinh thể màu vàng bay ra — đó là dấu hiệu của phong hiệu Thiên Vận Thất tử, danh hiệu thân phận chân chính cho đệ tử của Thiên Vận Tử. Người nhận phải bế quan cảm thụ tinh thể này; khi xuất quan sẽ được truyền thêm một bảo mệnh pháp bảo. Trong chương, Côn Bằng Tử của Hoàng hệ nhận khối tinh thể này.","nguon":["@c0469"]},{"id":"that-thai-luu-ly-quang","name":"Thất thải lưu ly quang","category":"khac","categoryLabel":"Thiên địa kỳ bảo","phamCap":"Thiên địa kỳ bảo (xếp thứ 93 Tu Chân Liên Minh)","soHuu":["Trần Đào","Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Đoá hoa sáu cánh sáu màu, thiên địa kỳ bảo xếp thứ 93 trong Tu Chân Liên Minh; Trần Đào cướp ở Hắc Mặc Tinh dâng cho Thiên Vận Tử.","detail":"Hoa mười năm mọc rễ, vạn năm nở một lần, nở liên tục sáu lần thì lần bảy mới toả ánh bảy màu; yêu thú nuốt vào cực lợi. Trần Đào đoạt được từ ba con thượng phẩm hoang thú ở Hắc Mặc Tinh rồi dâng làm lễ đại thọ vạn năm cho Thiên Vận Tử. Tôn trưởng lão thẩm định hoả hậu còn kém cánh thứ bảy, Thiên Vận Tử có thể khiến nở đủ.","nguon":["@c0470"]},{"id":"hat-chau-hap-thu-ma-luc","name":"Hạt châu hấp thu ma lực","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Triệu Hân Mộng"],"trangThai":"hong","blurb":"Hạt châu trắng tinh của Triệu Hân Mộng, hô ‘Thu’ hút ma lực hoá đen; dùng gài bẫy Vương Lâm rồi vỡ vụn.","detail":"Hạt châu trắng tinh, khi hô ‘Thu’ thì hút sạch ma lực và hoá đen toả âm hàn khí. Triệu Hân Mộng dùng nó hút ma lực do Hoá Ma chỉ sản sinh để cướp đoạt, nhưng Vương Lâm khiến ma lực hư ảo tự sụp, hạt châu sau đó vỡ vụn.","nguon":["@c0470"]},{"id":"truong-thang-den-tran-dao","name":"Trường thằng đen","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Trần Đào"],"trangThai":"dang-co","blurb":"Sợi dây dài màu đen như gân sinh vật của Trần Đào, toả khí tức hoang dã, rút ra để đối phó Hồn thú.","detail":"Trần Đào xé áo lộ nửa thân trên rồi rút ra một trường thằng đen trông như sợi gân của sinh vật, toả khí tức hoang dã, dùng nghênh chiến Hồn thú của Vương Lâm.","nguon":["@c0470"]},{"id":"tam-xoa-kich-do-ti","name":"Tam xoa kích của Cổ Thần Đồ Ti","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tuyệt thế (dự định)","soHuu":["Cổ Thần Đồ Ti"],"trangThai":"mat","blurb":"Pháp bảo Đồ Ti luyện lần thứ chín, mới ngưng hình chưa sinh hồn, được hóa thành cự sơn ba ngọn để ngưng kết sơn hồn.","detail":"Lần luyện bảo thứ chín cũng là cuối cùng khi Đồ Ti còn sống, ông dùng nhiều năm tìm tài liệu mới hoàn thành một thanh tam xoa kích. Pháp bảo mới ngưng hình chưa sinh hồn thể nên Đồ Ti thấm Cổ huyết lên thân nó rồi ném vào một tinh cầu cực lớn, hóa thành cự sơn ba ngọn núi để có sơn ý, ngưng kết sơn hồn, định đợi sau khi Hóa niệm trọng tu sẽ tới lấy làm tuyệt thế pháp bảo. Núi do tam xoa kích biến thành giống hệt ba ngọn núi Vương Lâm thấy ở Thiên Vận Tinh, nhưng Vương Lâm phủ định đây là nơi đó vì hai sườn là giả.","nguon":["@c0472"]},{"id":"tinh-the-phong-hieu-thien-van-that-tu","name":"Tinh thể phong hiệu Thiên Vận Thất tử","category":"khac","categoryLabel":"Tín vật phong hiệu","phamCap":"Tín vật","soHuu":["Trần Đào"],"trangThai":"dang-co","blurb":"Khối tinh thể trong suốt mang theo cảm ngộ phong hiệu Thiên Vận Thất tử của Tử hệ.","detail":"Khối tinh thể trong suốt Thiên Vận Tử lấy ra từ mi tâm, hóa thành tử hồng dung nhập mi tâm người thắng để họ tự cảm ngộ. Trao cho Trần Đào sau khi hắn thắng Vương Lâm; đây không phải lần đầu Trần Đào nhận phong hiệu này.","nguon":["@c0472"]},{"id":"bao-thap-dinh-nui-toai-tien","name":"Bảo tháp đỉnh ngọn núi trắng","category":"phap-bao","categoryLabel":"Bảo tháp","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Bảo tháp tỏa ánh sáng bảy màu trên đỉnh ngọn núi trắng, nơi Thiên Vận Tử ngồi quan sát khảo nghiệm.","detail":"Bảo tháp trên đỉnh ngọn núi trắng phủ Cửu U chi hàn, tỏa ánh sáng bảy màu, nhìn thấy được từ chỗ Vương Lâm dừng gần đỉnh trăm bước. Thiên Vận Tử ngồi trong tháp quan sát quá trình Vương Lâm leo Toái Tiên chi địa và khiếp sợ trước số bước hắn vượt qua.","nguon":["@c0472"]},{"id":"te-dan-bay-mau-thien-van","name":"Tế đàn bảy màu (Thiên Vận Tông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Trọng bảo tông môn","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Tế đàn cực lớn hạ xuống từ khe không trung, trên có vô số mộc bài bảy màu ghi danh đệ tử Thiên Vận Tông.","detail":"Một tòa Tế đàn bảy màu cực lớn hạ xuống từ cái khe Thiên Vận Tử xé ra giữa không trung, trên khắc đầy mộc bài bảy màu. Khi thu nhận đệ tử, lệnh bài khắc danh tự cháy hóa thành lửa tím bay về tế đàn lưu danh. Vương Lâm được ghi làm đệ tử thứ bảy của Tử hệ qua tế đàn này.","nguon":["@c0473"]},{"id":"bao-thap-thien-van-tong-mon","name":"Bảo tháp Thiên Vận","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Trọng bảo tông môn","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Tòa tháp bề ngoài bình thường trên đỉnh núi Tổng tông, ngưng tụ ánh sáng bảy màu hóa thành bóng dáng Thiên Vận Tử.","detail":"Bảo tháp Thiên Vận đặt trên các ngọn núi của Tổng tông tại Thiên Vận Tinh, bề ngoài bình thường nhưng có thể ngưng tụ ánh sáng bảy màu hóa thành bóng dáng Thiên Vận Tử để giao tiếp. Ánh sáng từ tháp tạo cầu vồng bảy màu đưa Vương Lâm lướt qua hơn bảy mươi bước còn lại tới dưới chân tháp.","nguon":["@c0473"]},{"id":"ngan-long-la-ban","name":"Ngân Long la bàn","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo di chuyển giúp Vương Lâm có tốc độ không thua kém ai khi ở ngoài tinh ngoại.","detail":"Vương Lâm dùng để di chuyển nhanh ngoài tinh ngoại; được điểm lại trong số sở học của hắn khi cân nhắc thần thông phòng thân, song chỉ hữu dụng tương đối với tu sĩ Vấn Đỉnh.","nguon":["@c0474"]},{"id":"ngoc-gian-bui-khi-ao-xam","name":"Ngọc giản (tạo từ bụi khí)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản Thiên Vận Tử áo xám hoá từ bụi khí để lại cho Vương Lâm sau khi hắn từ chối học Sát Lục Tiên quyết.","detail":"Người áo xám vung tay hoá bụi khí thành ngọc giản lơ lửng giữa không trung rồi biến mất; Vương Lâm bắt lấy, ánh mắt trầm ngâm. Nội dung ngọc giản chưa rõ.","nguon":["@c0474"]},{"id":"bao-phien-ngoc-bich","name":"Bảo phiến ngọc bích","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hứa Vân Sơn"],"trangThai":"dang-co","blurb":"Cây quạt gấp màu ngọc bích của Thiếu Tông Hứa Vân Sơn.","detail":"Cây quạt gấp màu ngọc bích Hứa Vân Sơn cầm trong tay, gõ gõ lòng bàn tay khi chờ đón Vương Lâm ngoài Truyền tống trận của Huyền Uyên Phái.","nguon":["@c0476"]},{"id":"lenh-bai-chu-that-vuong-lam","name":"Lệnh bài khắc chữ “Thất”","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài bên hông Vương Lâm khắc chữ “Thất”, biểu thị thân phận Tử hệ Lão Thất.","detail":"Lệnh bài đeo bên hông Vương Lâm, khắc một chữ “Thất”, biểu thị thân phận Tử hệ Lão Thất — đệ tử của Thiên Vận Tử.","nguon":["@c0476"]},{"id":"ngoc-gian-mau-xam-sat-luc-tien-quyet","name":"Ngọc giản màu xám (Sát Lục Tiên quyết)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối ngọc giản màu xám lưu giữ Sát Lục Tiên quyết, do Thiên Vận Tử áo xám trao cho Vương Lâm.","detail":"Ngọc giản chứa Sát Lục Tiên quyết — thực chất là một đạo Sinh chi lạc ấn ẩn chứa thần thông kỳ dị. Vương Lâm dung nhập tâm thần vào ngọc giản nghiên cứu suốt hơn một tháng nhưng tư chất không thượng giai nên không tìm được điểm khởi đầu.","nguon":["@c0477"]},{"id":"dieu-kim-qua","name":"Diệu Kim quả","category":"nguyen-lieu","categoryLabel":"Thiên tài địa bảo","phamCap":"Quý hiếm","soHuu":["Quách Tà Dật"],"trangThai":"dang-co","blurb":"Thiên tài địa bảo được sư thúc Quách Tà Dật coi trọng, nguồn cơn tranh chấp giữa hai bên kiếm tu.","detail":"Vật quý mà sư thúc Quách Tà Dật coi trọng; Thiên Cầm cô nương muốn lấy về sư môn của nàng. Quách Tà Dật mượn danh Đại La Kiếm Tông để chiếm phần lớn, chỉ hứa để lại một quả cho Thiên Cầm cô nương, gây ra mâu thuẫn.","nguon":["@c0478","@c0479"]},{"id":"ngoc-gian-ba-cho-yeu-thu","name":"Ngọc giản ba chỗ yêu thú","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Thường","soHuu":["Vương Lâm","Thiên Thai lão nhân"],"trangThai":"dang-co","blurb":"Ngọc giản Thiên Thai lão nhân lấy từ hư không, ghi ba nơi yêu thú tụ tập trên Địa Tinh.","detail":"Thiên Thai lão nhân lấy ra từ hư không, bên trong ghi ba chỗ yêu thú tụ tập trên Địa Tinh; trao cho Vương Lâm. Vương Lâm thần thức quét qua rồi rời đi tới Cực Bắc Địa Tinh.","nguon":["@c0478"]},{"id":"bao-kiem-co-xua-dai-la-kiem-tong","name":"Bảo kiếm cổ xưa (Đại La Kiếm Tông)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Quách Tà Dật","Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","Hai Kiếm Các Trưởng lão"],"trangThai":"dang-co","blurb":"Trường/bảo kiếm phong cách cổ xưa mà đệ tử và trưởng lão Đại La Kiếm Tông đeo theo, phát kiếm khí dày đặc.","detail":"Quách Tà Dật cùng ba lão già hắc y của Đại La Kiếm Tông đều đeo trường kiếm hoặc bảo kiếm mang phong cách cổ xưa, toả kiếm khí dày đặc, thể hiện đặc trưng kiếm tu của tông môn.","nguon":["@c0478"]},{"id":"van-thu-vat-nuoi-vuong-lam","name":"Văn thú","cn":"","category":"khac","categoryLabel":"Yêu thú / Vật nuôi","phamCap":"Nguyên Anh kỳ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Yêu thú đến từ tinh không, sống bằng cắn nuốt vạn vật, càng ăn càng mạnh; vật nuôi của Vương Lâm đang ở thời khắc sắp tiến hóa.","detail":"Văn thú là thú đến từ tinh không, không rõ vì sao năm đó xuất hiện ở Tu Ma Hải của Chu Tước Tinh. Hung tính của nó vượt xa yêu thú tu chân tinh thông thường, sống bằng cắn nuốt vạn vật — đan dược, thiên tài địa bảo, nội đan, huyết nhục — ăn càng nhiều càng mạnh. Nó có xúc tu lớn để đâm vào con mồi hút nội đan và tinh hoa huyết nhục, chỉ để lại bộ xương khô. Thực lực dừng ở Nguyên Anh kỳ nhưng yêu thú Hóa Thần gặp nó cũng khiếp sợ. Theo Vương Lâm đến nay đã nuốt vô số bảo vật; mỗi lần nuốt thân lóe bạch mang (giống năm đó nuốt bạch sắc trường ngân trong Toái Tinh Loạn), lông tơ càng yêu dị. Đến chương này nó ở thời khắc mấu chốt, sắp đột phá tiến hóa; Vương Lâm thấy hình ảnh một tinh cầu đầy Văn thú vô tận với xúc tu dữ tợn, mắt ẩn đốm lửa.","nguon":["@c0479"]},{"id":"kim-linh-can","name":"Kim linh căn","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Căn cốt kim thuộc tính hình thành khi toàn bộ Diệu Kim quả tàn héo dung nhập vào gốc; kim linh thú nuốt vào sẽ đại khai thần trí.","detail":"Khi tất cả Diệu Kim quả trên một phiến hoa tàn héo, chúng dung nhập vào gốc mà hình thành kim linh căn. Nếu quả bị lấy đi quá nhiều thì không hình thành được kim linh căn. Kim linh thú nuốt kim linh căn vào sẽ đại khai thần trí. Theo ký ức Cổ Thần Đồ Ti mà Vương Lâm nắm giữ, nuốt kim linh căn còn khiến thân thể cứng rắn, là thuốc bổ hiếm có đối với Cổ Thần thuở nhỏ — đây mới là cách dùng chân chính mà các tu sĩ Đại La Kiếm Tông không biết.","nguon":["@c0480"]},{"id":"ngoc-gian-do-thach-phuong","name":"Ngọc giản màu đỏ (Kiếm phong chi cấm)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thạch Phương"],"trangThai":"da-dung","blurb":"Khối ngọc giản đỏ chứa cấm thuật Kiếm phong chi cấm của Thạch Phương.","detail":"Pháp bảo dạng ngọc giản màu đỏ; khi Thạch Phương kết kiếm chỉ phát động, nó bay vào sơn cốc rồi tan thành vô số sợi tơ đỏ đan thành lưới đỏ, kết hợp kỳ hiệu điện quang dựng nên phong ấn nghiêm mật giam nam tử áo trắng và đàn Cửu Lê trùng.","nguon":["@c0481"]},{"id":"guong-dong-lao-gia-lun","name":"Gương đồng một mặt","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lão già lùn (Trưởng lão Đại La Kiếm Tông)"],"trangThai":"hong","blurb":"Gương đồng một mặt của lão già lùn, tỏa thanh quang chống bụi khí nhưng bị phá vỡ.","detail":"Lão già lùn ném ra một cái gương đồng một mặt, đón gió bành trướng cao tầm ba thước, tản thanh quang bao phủ đoàn bụi khí của kẻ mạnh. Sau câu nói lạnh lẽo từ bụi khí, thanh quang sụp đổ tiêu tan và gương đồng vỡ vụn răng rắc.","nguon":["@c0481"]},{"id":"lieu-diep-phi-kiem-thach-phuong","name":"Liễu diệp phi kiếm","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Phương"],"trangThai":"mat","blurb":"Bản mạng phi kiếm hình lá liễu của Thạch Phương, dung nguyên thần ly thể.","detail":"Phi kiếm hình lá liễu chứa nguyên thần ly thể của Thạch Phương, mang theo ngọn lửa xanh áp sát mi tâm đối thủ. Bị tiên ảnh của Vương Lâm đánh chấn động khiến hào quang ảm đạm; về sau nguyên thần dùng nó xuyên mi tâm Quách Tà Dật để đoạt xá.","nguon":["@c0483"]},{"id":"ngoc-gian-doat-xa-sieu-toc","name":"Ngọc giản đoạt xá siêu tốc","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản Thạch Phương ghi lại phương pháp đoạt xá cực nhanh và thần thông mượn xử nữ chữa thương.","detail":"Để mua mạng, Thạch Phương ghi vào ngọc giản phương pháp đoạt xá siêu tốc cùng thần thông mượn xử nữ chữa thương rồi ném cho Vương Lâm. Vương Lâm thu giữ, đánh giá là có chút giá trị.","nguon":["@c0483"]},{"id":"ngoc-gian-dieu-hoa-do-ti","name":"Ngọc giản điều hoà","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Vật dẫn pháp thuật","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Nhiều khối ngọc giản lớn được khắc văn, đặt cạnh đoá hoa làm vật dẫn cho phương pháp điều hoà của Vương Lâm.","detail":"Vương Lâm lấy ra nhiều ngọc giản lớn, khắc văn rồi đặt quanh đoá Kim hoa thay cho xương cốt yêu thú mà Cổ Thần Đồ Ti vốn dùng. Khi Chú ngôn được thốt ra, ánh sáng vàng phá nổ lần lượt từng ngọc giản thành tro, năng lượng dồn vào ép hoa và Diệu Kim quả héo rũ. Vì ngọc giản kém hơn xương cốt yêu thú nên thành quả chỉ đạt bốn kim linh căn.","nguon":["@c0484"]},{"id":"huyet-ngoc-tuong-dieu-tich-tuyet","name":"Huyết ngọc (tượng huyết sắc)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / phương tiện","phamCap":"Không rõ","soHuu":["Diêu Tích Tuyết","Huyết Tổ Diêu Tinh Hải"],"trangThai":"dang-co","blurb":"Bức tượng huyết sắc khổng lồ bằng ngọc thạch của Huyết Tổ, tỏa hồng quang và mùi máu tanh, làm phương tiện bay trong tinh không.","detail":"Khi Diêu Tích Tuyết đến ngoài Đông Hải Yêu Linh, nàng ngồi khoanh chân trên bức huyết ngọc khổng lồ này; tượng phát ra đạo hồng quang che phủ bầu trời cùng mùi máu tanh nồng đậm khiến cả vùng biến thành thế giới màu đỏ.","nguon":["@c0486"]},{"id":"truyen-tong-ngoc-gian-ton-nhuoc-nam","name":"Truyền tống ngọc giản bám theo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo truyền tống","phamCap":"","soHuu":["Tôn Nhược Nam"],"trangThai":"dang-co","blurb":"Ngọc giản truyền tống của cha Tôn Nhược Nam, biến người dùng thành sợi tơ trắng để bám theo người khác qua cầu vồng truyền tống.","detail":"Khi kích hoạt, ngọc giản phát bạch quang bao bọc toàn thân, biến người dùng thành một sợi tơ trắng có thể phóng vào và bám theo cầu vồng truyền tống của người khác. Tôn Nhược Nam lén lấy trộm của cha để bám theo Vương Lâm tới Đông Hải Yêu Linh.","nguon":["@c0487"]},{"id":"dai-kiem-co-kiem-tieu-thap-nhi-tu","name":"Đại kiếm cổ của Kiếm Tiếu Thập Nhị Tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo - kiếm","phamCap":"","soHuu":["Kiếm Tiếu Thập Nhị Tử"],"trangThai":"dang-co","blurb":"Mười hai thanh đại kiếm rất cổ của Kiếm Tiếu Thập Nhị Tử, mỗi thanh huyễn hóa một loại yêu thú.","detail":"Mười hai cao thủ của Đại La Kiếm Tông mỗi người mang một thanh đại kiếm cổ; mỗi thanh có thể huyễn hóa thành một loại yêu thú khác nhau, tạo nên mười hai con thú hình dạng khác nhau đi theo Kiếm Tôn.","nguon":["@c0487"]},{"id":"kiem-hon-nu-quan-tien-gioi","name":"Kiếm hồn của nữ quân tiên giới","cn":"","category":"khac","categoryLabel":"Kiếm hồn","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Đạo kiếm hồn uy lực kinh người, vốn là vật của một nữ quân tiên giới, bị Kiếm Tôn nhốt trong Đông Hải Yêu Linh.","detail":"Năm xưa khi Kiếm Tôn từ tiên giới quay về thì bị đạo kiếm hồn này liên tục làm phiền, uy lực của nó khiến lão kinh hãi. Do không dùng được, lão dùng bí thuật nhốt nó vào Đông Hải Yêu Linh và định mượn thủy triều hút nó chìm sâu vĩnh viễn để không rơi vào tay người khác.","nguon":["@c0487"]},{"id":"hat-chau-tu-chan-lien-minh","name":"Hạt châu (Tu Chân Liên Minh truy tìm)","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Một hạt châu bí ẩn được Tu Chân Liên Minh phát thông cáo truy tìm mấy vạn năm trước, treo thưởng cả bộ thượng phẩm tiên thuật hoàn chỉnh.","detail":"Mấy vạn năm trước Tu Chân Liên Minh từng phát thông cáo tìm hạt châu này, treo thưởng một bộ thượng phẩm tiên thuật hoàn chỉnh, phần thưởng lớn chưa từng có. Theo lời Tham Lang, vết thương của hắn có liên quan đến hạt châu, và hắn đang bị người giữ hạt châu bức bách nên mới chạy đường xa tới Thiên Vận Tinh cầu Kiếm Tôn Lăng Thiên Hậu xuất thủ. Bản chất, lai lịch cụ thể của hạt châu chưa được tiết lộ.","nguon":["@c0488"]},{"id":"lenh-bai-kim-quang-dong-hai","name":"Lệnh bài kim quang khắc ký hiệu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Khối lệnh bài lấp lánh kim quang khắc ký hiệu, nằm sâu trong con sóng hồng quang cuối của thủy triều cửa Đông Hải Yêu Linh; vật trung tâm khiến mọi cao thủ đại biến sắc.","detail":"Khi thủy triều hồng quang sắp rút hết về cửa Đông Hải Yêu Linh, con sóng cuối quỷ dị ngăn cản cả thần thức lẫn ánh mắt thăm dò. Vương Lâm vận thần thông ánh mắt phá vỡ hồng quang mới nhìn rõ ở sâu bên trong một khối lệnh bài lấp lánh kim quang, trên khắc ký hiệu. Vừa thấy lệnh bài, Thiên Vận Tử, Kiếm Tôn Lăng Thiên Hậu cùng các lão quái thành danh Thiên Vận Tinh đều đại biến sắc và điên cuồng lao ra tranh đoạt. Lai lịch và công dụng chưa được hé lộ.","nguon":["@c0490"]},{"id":"thanh-dai-kiem-ri-set","name":"Thanh đại kiếm rỉ sét hình cánh cửa","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Thanh kiếm lớn hình như một cánh cửa, lấp lánh kim quang nhưng mơ hồ rỉ sét và có chỗ vỡ nát, loé lên trong hồng quang phương xa rồi biến mất.","detail":"Giữa thủy triều bảo vật rút về cửa Đông Hải Yêu Linh, trong một đạo hồng quang phương xa hiện ra một thanh đại kiếm hình dáng tựa một cánh cửa, lấp lánh kim quang song mơ hồ rỉ sét và có chỗ vỡ nát. Nó chỉ loé lên một cái rồi biến mất, nhưng đủ khiến ánh mắt Vương Lâm ngưng trọng. Lai lịch chưa rõ.","nguon":["@c0490"]},{"id":"thien-kim-thuong","name":"Thiên Kim Thượng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Một trong các vật luyện khí tương đối tốt mà Vương Lâm nhận ra từ ký ức Cổ Thần Đồ Ti, trôi nổi trong hồng quang thủy triều cửa Đông Hải.","detail":"Vật luyện khí quý nằm trong ký ức Cổ Thần Đồ Ti, được hồng quang cuốn theo khi thủy triều rút về cửa Đông Hải Yêu Linh; Vương Lâm thoáng nhận ra giữa dòng bảo vật vô chủ.","nguon":["@c0490"]},{"id":"quynh-hoa-dich","name":"Quỳnh Hoa Dịch","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Vật luyện khí tốt trong ký ức Cổ Thần Đồ Ti, trôi trong hồng quang thủy triều cửa Đông Hải.","detail":"Một trong những vật luyện khí quý mà Vương Lâm nhận ra nhờ ký ức Cổ Thần Đồ Ti khi hồng quang cuốn vô số bảo vật vô chủ về cửa Đông Hải Yêu Linh.","nguon":["@c0490"]},{"id":"thuy-mac-thach","name":"Thủy Mặc Thạch","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Vật luyện khí tốt trong ký ức Cổ Thần Đồ Ti, trôi trong hồng quang thủy triều cửa Đông Hải.","detail":"Một trong những vật luyện khí quý Vương Lâm nhận ra giữa dòng hồng quang rút về cửa Đông Hải Yêu Linh, theo ký ức Cổ Thần Đồ Ti.","nguon":["@c0490"]},{"id":"linh-te-giac","name":"Linh Tê Giác","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Vật luyện khí tốt trong ký ức Cổ Thần Đồ Ti, trôi trong hồng quang thủy triều cửa Đông Hải.","detail":"Một trong những vật luyện khí quý Vương Lâm thoáng nhận ra trong hồng quang cuốn về cửa Đông Hải Yêu Linh, theo ký ức Cổ Thần Đồ Ti.","nguon":["@c0490"]},{"id":"tien-kiem-lang-thien-hau","name":"Tiên kiếm (Lăng Thiên Hậu)","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Tiên khí","soHuu":["Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Thanh kiếm Lăng Thiên Hậu định luyện hóa thành yêu kiếm.","detail":"Thanh Tiên kiếm Lăng Thiên Hậu định luyện hóa hoàn toàn, lấy chín chín yêu linh quy nhất để luyện thành yêu kiếm, nhằm nắm chắc việc thu lệnh bài Đông Hải; hắn dự định dùng hai trăm năm bế quan tại đông bộ Đại La tinh để hoàn thành.","nguon":["@c0491"]},{"id":"lenh-bai-dong-hai","name":"Lệnh bài Đông Hải","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Vật trong tầng sóng không khí màu đỏ, liên quan đại bí mật Thiên Vận Tinh.","detail":"Vật còn lại trong tầng sóng không khí màu đỏ tại cánh cửa Đông Hải yêu linh, liên quan một đại bí mật của Thiên Vận Tinh; lần này có tất cả ba cái, là mục tiêu tranh đoạt của các lão quái thành danh. Thiên Vận Tử ước định năm trăm năm sau sẽ tụ lại tranh đoạt.","nguon":["@c0491"]},{"id":"xuong-thu-den-thien-van-tu","name":"Xương thú đen kịt","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thiên Vận Tử"],"trangThai":"dang-co","blurb":"Mẩu xương thú tỏa khí tà dị Thiên Vận Tử dùng để bói toán.","detail":"Vài mẩu xương thú cực sáng, tỏa khí tức tà dị; Thiên Vận Tử đặt cạnh mình trong bảo tháp bảy màu rồi rải quanh để quan sát, bói toán vận may của Vương Lâm.","nguon":["@c0491"]},{"id":"dan-duoc-co-bon-boi-nguyen","name":"Đan dược cố bổn bồi nguyên","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Mấy chục viên đan dược cố bổn bồi nguyên đựng trong ba bình ngọc, Vương Lâm tặng tộc nhân sơn cốc làm lời tạ lỗi.","detail":"Vương Lâm ném ba bình ngọc chứa đan dược cố bổn bồi nguyên xuống cho tộc nhân Âu Dương Hoa, coi như tạ lỗi vì đã hao tâm phá trận pháp chỉ để thấy một thôn xóm phàm nhân. Âu Dương Hoa mở bình hít một hơi liền sắc mặt đại biến, vội cất vào lồng ngực.","nguon":["@c0495"]},{"id":"buc-tranh-hoang-long","name":"Bức tranh Hoàng Long","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Bức tranh ố vàng nứt nẻ treo ở góc kín trong nhà Âu Dương Hoa, vẽ Hoàng Long thượng tiên nhìn một hư ảnh trong hắc vụ.","detail":"Bức tranh niên đại rất lâu, ố vàng và nứt nẻ, treo ở vị trí không bắt mắt trong căn nhà tròn của Âu Dương Hoa. Tranh vẽ một nam tử trung niên khoảng bốn mươi tuổi mặc trang phục kỳ dị, tay phải tạo ấn ký cổ quái trước ngực, nhìn về phía xa nơi có một hư ảnh ẩn hiện trong màn sương đen không rõ là vật gì. Âu Dương Hoa khẳng định người trong tranh chính là Hoàng Long thượng tiên; cái tên khiến Vương Lâm chấn động nguyên thần.","nguon":["@c0495"]},{"id":"ngoc-yeu-linh-ket-tinh-tien-luc","name":"Ngọc yêu linh","cn":"","aliases":["Kết tinh tiên lực"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thấp (theo lời dân bản địa)","soHuu":["Âu Dương Hoa","Vương Lâm"],"trangThai":"da-dung","blurb":"Khối trắng như thủy tinh hình lục giác khảm trong vách đá xanh thẫm đáy sơn cốc; người bên ngoài gọi kết tinh tiên lực, dân nơi yêu linh gọi ngọc yêu linh.","detail":"Ngọc yêu linh là một khối trắng như thủy tinh hình lục giác khảm chắc giữa một vách đá màu xanh thẫm không ăn khớp bốn phía, nằm tại đáy sơn cốc hình hồ lô. Nó toát ra ba động tựa tiên lực nhưng thực chất chứa yêu lực — khí tức cực lạnh, trông như tiên lực nhưng lộ vẻ yêu dị. Dân bản địa dùng nó chữa trị thương cho tộc nhân, song phẩm bậc không cao, kém xa đan dược của người bên ngoài. Vương Lâm chụp l���y tinh thạch khiến vách đá run rẩy ầm ầm như địa long cuộn mình, rồi hấp thu yêu lực vào đan điền.","nguon":["@c0496"]},{"id":"binh-ngoc-dan-duoc-vuong-lam","name":"Bình ngọc đan dược (Vương Lâm)","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hơn mười bình ngọc đan dược trong túi trữ vật của Vương Lâm; là trọng bảo ở nơi yêu linh vì dân bản địa không có tài liệu luyện chế.","detail":"Hơn mười bình ngọc đan dược được Vương Lâm lấy ra cho bay một vòng rồi thu lại để mặc cả với Âu Dương Hoa. Ở nơi yêu linh, đan dược của người bên ngoài luôn được coi là trọng bảo bởi dân bản địa không có tài liệu luyện chế. Vương Lâm dùng số đan dược này để đổi lấy ngọc yêu linh.","nguon":["@c0496"]},{"id":"yeu-luc-ket-tinh","name":"Yêu lực kết tinh","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên / Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Yêu lực trong cơ thể yêu linh kết tinh thành, giống tiên lực nhưng đầy tính quỷ dị, là mục tiêu tranh đoạt chém giết của yêu linh Đông Hải.","detail":"Yêu lực trong cơ thể yêu linh kết tinh lại, tính chất giống tiên lực nhưng đầy quỷ dị. Hít hoặc hấp thu vào khiến cơ thể cực thoải mái ngây ngất, giúp hơi thở và tiên lực dung hợp mà đẩy cao tu vi. Yêu linh Đông Hải chém giết lẫn nhau cốt để cướp đoạt yêu lực kết tinh của đối phương; nó còn ẩn chứa tác dụng khác chưa rõ, từng gây gió tanh mưa máu nhiều năm. Vương Lâm dùng hơn mười bình ngọc đổi lấy phần kết tinh duy nhất của thung lũng Hồ Lô Cốc để nghiên cứu.","nguon":["@c0497"]},{"id":"phi-kiem-la-mo","name":"Phi kiếm của La mỗ","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"","soHuu":["La mỗ"],"trangThai":"hong","blurb":"Phi kiếm hắc y nam tử đạp lên di chuyển; bị kiếm tiên Vương Lâm làm rạn rồi dùng làm Kiếm toái.","detail":"La mỗ đạp phi kiếm này lạnh lùng đứng xem. Khi giao đấu, kiếm quang của Vương Lâm làm phi kiếm rạn một vết nhỏ khiến y nổi giận; sau đó y dùng chính tế kiếm này thi triển Kiếm toái, vỡ vụn nổ tung.","nguon":["@c0498"]},{"id":"loan-dao-vuong-lam","name":"Loan đao (Vương Lâm)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đao pháp bảo tốc độ cực nhanh của Vương Lâm, dùng bám sát truy kích đối thủ.","detail":"Vũ khí đao của Vương Lâm với tốc độ cực nhanh, bám sát Hắc y nam tử như tủy nhập xương. Khi đối phương thi triển Ma cấm, loan đao xuyên thấu Quỷ ảnh nhưng vô tác dụng, đồng thời bị vô số tơ đen nồng đậm tản ra từ thân Hắc y nam tử cản không cho bay vào gần bản thể.","nguon":["@c0499"]},{"id":"xa-than-xa-tien-nhan-vuong-lam","name":"Xạ Thần Xa","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật tiên nhân","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bảo vật do tiên nhân luyện chế, bên trong phong ấn một Hồn thú bất khuất, mở bằng Cửu Tự Chân Ngôn.","detail":"Xạ Thần Xa là bảo vật do tiên nhân luyện chế. Bên trong phong ấn một Hồn thú cao lớn, bất khuất, tương truyền dám nuốt cả tiên nhân và thường không chịu nghe lời. Vương Lâm mở Xạ Thần Xa bằng Cửu Tự Chân Ngôn — mỗi đạo phong ấn cần một chữ chân ngôn — rồi điều khiển Hồn thú nhằm thẳng Hắc y nam tử, buộc đối thủ phải bỏ thân xác cho nguyên thần chạy trốn.","nguon":["@c0500"]},{"id":"thien-quy-quy-anh","name":"Thiên Quỷ (Quỷ ảnh)","category":"khac","categoryLabel":"Quỷ vật","phamCap":"Quỷ linh","soHuu":["Hắc y nhân (mặt sẹo)"],"trangThai":"mat","blurb":"Quỷ vật của Hắc y nam tử, nuốt hồn thể để tăng quỷ lực; bị ép tới mức tự sinh hắc quang bỏ trốn.","detail":"Thiên Quỷ, còn gọi Quỷ ảnh, là quỷ vật của Hắc y nam tử, dùng nuốt hồn thể để tăng quỷ lực. Trong trận với Vương Lâm, nó bị dẫn dụ nhằm vào Anh Biến chủ hồn, đã hấp thu một phần tiên lực của chính Hắc y nam tử. Khi bị chủ nhân cố thu hồi bằng tơ đen, Thiên Quỷ hạ quyết tâm, tự sinh hắc quang bao phủ để không tan biến, xuyên qua yêu linh khí lãng bỏ trốn ra xa, mang theo tiên lực đã hấp thu; chủ hồn của Vương Lâm truy kích theo.","nguon":["@c0500"]},{"id":"dai-phien-hac-quang-vuong-lam","name":"Đại phiên (hắc quang)","category":"phap-bao","categoryLabel":"Cờ phướn","phamCap":"Pháp bảo","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cây đại phiên cao ba trượng Vương Lâm phun ra từ miệng để triệu xuất chủ hồn.","detail":"Đại phiên là cây cờ phướn hắc quang cao ba trượng mà Vương Lâm phun ra từ miệng và ôm gọn trong tay. Từ đại phiên hiện ra mấy chủ hồn — gồm cả tàn hồn kỳ lân — gào thét lao ra, được dùng làm mồi nhử Quỷ ảnh để Vương Lâm thừa cơ ôm trọn nó.","nguon":["@c0500"]},{"id":"yeu-tinh-cua-la-van","name":"Yêu tinh của La Vân","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối yêu tinh trong nguyên thần đan điền La Vân, tương đương hai giáp yêu lực.","detail":"Vương Lâm lấy ra khỏi nguyên thần đan điền La Vân; khối yêu tinh này tương đương hai giáp yêu lực. Cộng thêm một giáp yêu lực hắn hấp thu khi ở thung lũng là vừa đủ ba giáp — điều kiện nhập Thiên Yêu quận trong vùng đất yêu linh.","nguon":["@c0502"]},{"id":"co-yeu-chi-linh","name":"Cổ yêu chi linh","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"khong-ro","blurb":"Vật do thiên địa tự nhiên hóa thành, mỗi quận trong vùng đất yêu linh phong ấn một, mang nhiều thần thông.","detail":"Tu sĩ dung hợp được Cổ yêu chi linh thì tu vi tăng nhiều lần và đắc một số thần thông hùng mạnh, có tỉ lệ nhất định tiến vào cảnh giới thần chi thủy. Trong vạn năm chỉ chưa đến mười người chân chính đạt được; cổ yêu cứ mười vạn năm tiến hóa một lần, một khi bị dung hợp phải cần trăm vạn năm mới sinh ra cổ yêu mới. Muốn đạt phải có chiến công, là người ngoài đến và đủ yêu lực.","nguon":["@c0502"]},{"id":"thien-quy-ban-mang-la-van","name":"Thiên quỷ (bản mạng quỷ linh của La Vân)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["La Vân"],"trangThai":"hong","blurb":"Một trong chín bản mạng quỷ linh của Thiên Quỷ Đạo, con yếu nhất, được Sư tôn ban cho La Vân nhưng đã phản chủ.","detail":"Vật thần thông riêng của Thiên Quỷ Đạo, sinh ra từ hư vô và vô hình. Do La Vân tu luyện quá ngắn nên Thiên quỷ phản bội, mất máu huyết tương liên nên cực kỳ suy yếu, trốn trong khe rãnh ở bình nguyên. Nếu chịu qua bảy ngày sẽ không cần máu huyết, qua bốn chín ngày sẽ khôi phục hoàn toàn thành vật tàng hình đi khắp thiên hạ. Bị Vương Lâm dùng thuật đám bụi khí hóa hàn quang truy diệt khi còn suy yếu.","nguon":["@c0502"]},{"id":"ban-mang-chi-hoa-thien-quy","name":"Bản mạng chi hỏa (Quỷ hỏa)","cn":"","category":"khac","categoryLabel":"Bản mạng hỏa","phamCap":"","soHuu":["Thiên quỷ"],"trangThai":"dang-co","blurb":"Đám lửa màu lục là thủ đoạn công kích mạnh nhất của Thiên quỷ, chuyên đốt nguyên thần.","detail":"Bản mạng hỏa của Thiên quỷ, đám lửa màu lục tựa biển lửa, không đốt thân thể mà chuyên thiêu thẳng nguyên thần. Thiên quỷ giả vờ suy yếu rồi phun ra hòng bao trùm và hủy Côn Cực Tiên, nhưng bị một đạo kim quang quỷ dị từ Côn Cực Tiên chụp tắt trong nháy mắt.","nguon":["@c0503"]},{"id":"yeu-gian-vuong-lam","name":"Yêu giản (ngọc giản luyện hồn)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm","Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Ngọc giản Vương Lâm chế tác, gần giống ‘yêu giản’ trong ghi chép tổ tiên, chứa khẩu quyết thuật luyện hồn.","detail":"Ngọc giản do Vương Lâm chế tác tại vùng đất yêu linh, được lão xác nhận gần như ‘yêu giản’ qua trí nhớ về bản ghi chép tổ tiên La Vân. Bên trong chứa khẩu quyết thuật luyện hồn; người dùng phải dán ngọc giản tại mi tâm, ngưng thần tưởng tượng mới nhìn thấu nội dung. Âu Dương Hoa ban đầu thử mãi không cảm nhận được, sau khi được đả thông kinh mạch lên nhị tinh mới đọc được khẩu quyết.","nguon":["@c0504"]},{"id":"ba-giap-yeu-tinh","name":"Ba giáp yêu tinh","cn":"","category":"khac","categoryLabel":"Yêu tinh","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối yêu tinh do Vương Lâm dung hợp hai khối thành một sau ba tháng nghiên cứu; ẩn yêu lực vô biên.","detail":"Sau ba tháng nghiên cứu yêu tinh, Vương Lâm dung hợp hai khối thành một khối duy nhất gọi là ‘Ba giáp yêu tinh’: bên trong ẩn yêu lực vô biên, bên ngoài có nhiều xúc tu mờ quỷ dị. Khi Vương Lâm nuốt vào, yêu lực khuếch tán từ đan điền khiến toàn thân biến thành trạng thái yêu dị (đôi đồng tử dựng đứng hình quả trứng), song vận chuyển toàn bộ chỉ đạt Trúc Cơ kỳ vì số lượng yêu lực chưa đủ. Rút yêu lực trở về yêu tinh thì tiên lực lưu chuyển bình thường, hắn trở lại trạng thái siêu phàm — cơ chế biến đảo yêu lực và tiên lực này hắn nhận thấy có thể dùng để che giấu hơi thở.","nguon":["@c0504"]},{"id":"hon-phien-chi-moc","name":"Hồn phiên chi mộc","aliases":["Hồn phiên (vùng đất yêu linh)"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Vật mà cư dân vùng đất yêu linh dùng yêu lực để tu luyện, chế tác sau khi thuật luyện hồn đạt giai đoạn ba.","detail":"Hồn phiên chi mộc là vật cư dân vùng đất yêu linh dùng yêu lực tu luyện. Giai đoạn ba của thuật luyện hồn chính là bước chuẩn bị chế tác hồn phiên cho chính mình; nơi không có linh lực mà chỉ có yêu linh, dùng yêu lực luyện hồn phiên thì có thể thành công. Thanh niên có thiên phú trong cốc ba tháng đã đạt giai đoạn ba, bước vào khâu tự chế tác hồn phiên.","nguon":["@c0504"]},{"id":"hon-phien-thay-the-thien-van","name":"Hồn phiên thay thế (Thiên Vận Tinh)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thập Tam","Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Cây phiên phong ấn hồn phách chế theo phương pháp ứng biến của Vương Lâm, có phân cấp thập/bách/thiên/vạn theo uy lực.","detail":"Hồn phiên là pháp bảo dùng luyện hóa và phong ấn hồn phách dã thú; phân cấp thập, bách, thiên, vạn hồn phiên theo uy lực. Bản chế tại Thiên Vận Tinh dùng cươn thụ chi mộc và da dã thú thay tài liệu thiếu, chỉ phong ấn được không quá mười hồn phách. Cây do Thập Tam chế thành dài bảy thước sau ba lần thất bại, triệu được hồn phách sư tử cánh dài. Mọi hồn thú phong ấn vào đó đều ẩn sơ hở do Vương Lâm cài, chịu hắn khống chế.","nguon":["@c0505"]},{"id":"tieu-phien-au-duong-hoa","name":"Tiểu phiên ba tấc (Âu Dương Hoa)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Cây tiểu phiên dài ba tấc của Âu Dương Hoa, triệu được hồn phách chim sẻ ra chiến đấu.","detail":"Khi sư tử cánh dài phản phệ Thập Tam, Âu Dương Hoa lấy ra cây tiểu phiên dài ba tấc và triệu một con chim sẻ (hồn phách) lao tới chặn. Chim sẻ bị tiếng gầm xuyên thấu của sư tử làm chậm lại nên không cản kịp.","nguon":["@c0505"]},{"id":"cuon-thu-chi-moc","name":"Cươn thụ chi mộc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Loài cây đặc hữu ở Thiên Vận Tinh, nguyên liệu chế hồn phiên thay thế.","detail":"Cươn thụ chi mộc là loài cây đặc hữu nơi yêu linh Thiên Vận Tinh, được Vương Lâm dùng làm nguyên liệu chính để chế hồn phiên thay thế khi thiếu tài liệu.","nguon":["@c0505"]},{"id":"ngoc-gian-che-hon-phien-moi","name":"Ngọc giản phương pháp chế hồn phiên mới","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm","Thập Tam"],"trangThai":"dang-co","blurb":"Ngọc giản Vương Lâm khắc phương pháp chế hồn phiên thay thế, đặt ở mi tâm để xem.","detail":"Sau khi sáng tạo phương pháp chế hồn phiên ứng biến, Vương Lâm khắc nó lên ngọc giản và ném cho Thập Tam cùng Âu Dương Hoa. Thập Tam đặt ngọc giản ở mi tâm xem, run rẩy kích động rồi quỳ lạy Vương Lâm ba lạy.","nguon":["@c0505"]},{"id":"yeu-thang","name":"Yêu thang","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Chất lỏng xanh biếc nổi bong bóng dùng để đồng hóa người ngoại tộc thành tộc nhân mới.","detail":"Chất lỏng màu xanh biếc nổi bong bóng, mùi khó chịu, đựng trong thùng gỗ lớn. Cho người ngoại tộc bị bắt uống vào sẽ quên hết mọi việc, sau đó bị thì thầm tên mới và chuyện trong bộ tộc bên tai, dần biến thành tộc nhân mới. Là phương pháp thu nạp tộc nhân của các bộ lạc lẻ loi nơi yêu linh; Vương Lâm xem là tầm thường, kém xa mê hồn thuật và vô dụng với người tu đạo.","nguon":["@c0506"]},{"id":"yeu-tinh-he-giap","name":"Yêu tinh (hệ giáp)","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Yêu tinh phân theo ‘giáp’, là tài nguyên cốt lõi để lập công đổi khẩu quyết nơi yêu linh.","detail":"Yêu tinh phân cấp theo ‘giáp’: khối nhị giáp lớn cỡ ngón cái ẩn trong đá đen thô ráp. Vương Lâm bóp vỡ đá, nuốt nhị giáp yêu tinh rồi dung hợp với yêu tinh trong đan điền thành ngũ giáp yêu tinh. Là tài nguyên cốt lõi để tộc nhân lập công đổi khẩu quyết Luyện Hồn Thuật.","nguon":["@c0506"]},{"id":"co-ton-hon-vuong-lam","name":"Cờ Tôn Hồn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Truyền thừa Luyện Hồn","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lá cờ thu giam nguyên thần kẻ địch thành hồn phách bổ sung cho Hồn phiên.","detail":"Vương Lâm giam nguyên thần lão già áo trắng vào cờ Tôn Hồn, biến hắn thành một hồn phách trong cờ; xác lão bị chủ hồn đốt thành tro.","nguon":["@c0507"]},{"id":"soi-to-hong-yeu-vat-thap-tam","name":"Sợi tơ hồng yêu vật ký sinh","cn":"","category":"khac","categoryLabel":"Yêu vật","phamCap":"Yêu vật bộ lạc lớn","soHuu":["Lão già áo trắng (Thiên Thủy)"],"trangThai":"hong","blurb":"Sợi tơ hồng dài một trượng được lão áo trắng hạ vào ngực Thập Tam để biến hắn thành chiến thư sống.","detail":"Chuyển động quỷ dị như rắn trong cơ thể, kháng cự khi bị rút; bị tiên lực Vương Lâm đốt thành tro khi rút ra.","nguon":["@c0507"]},{"id":"cay-co-ky-quai-thap-tam","name":"Cây cờ kỳ quái (tiểu kỳ hồn phiên của Thập Tam)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Hồn phiên nhỏ","soHuu":["Thập Tam","Lão già áo trắng (Thiên Thủy)"],"trangThai":"bi-cuop","blurb":"Mấy cây cờ nhỏ Thập Tam dùng để xuất yêu hồn tấn công, bị lão áo trắng cướp.","detail":"Lão áo trắng cướp mấy cây cờ này, cho rằng khẩu quyết trong đầu Thập Tam là thật nhưng chưa đầy đủ nên dùng chiến thư sống dụ Vương Lâm để moi nốt phương pháp sử dụng.","nguon":["@c0507"]},{"id":"ngoc-gian-truyen-am-bo-lac-luyen-hon","name":"Ngọc giản truyền âm (bộ lạc Luyện Hồn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cặp ngọc giản truyền âm Vương Lâm tự luyện làm đường liên hệ trước khi rời bộ lạc.","detail":"Vương Lâm luyện hai cái trong nửa tháng, một mang theo bên người, một để lại bộ lạc Luyện Hồn để liên hệ và phòng đường lui khi đi Cổ Yêu thành.","nguon":["@c0508"]},{"id":"ngoc-gian-luyen-the-thuat-thap-tam","name":"Ngọc giản ghi Luyện Thể thuật","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Thập Tam"],"trangThai":"dang-co","blurb":"Ngọc giản Vương Lâm ghi Luyện Thể thuật của Cự Ma Tộc rồi trao cho Thập Tam.","detail":"Vương Lâm ghi công pháp Luyện Thể thuật do hắn tổng kết từ Cự Ma Tộc vào ngọc giản, trao Thập Tam để tu hành; nếu thành tựu sẽ truyền thêm khẩu quyết tầng thứ nhất Cổ Thần.","nguon":["@c0508"]},{"id":"ly-yeu-thang","name":"Ly Yêu thang","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Hổ Bào"],"trangThai":"da-dung","blurb":"Thang thuốc khiến người uống trở thành thành viên bộ lạc Luyện Hồn.","detail":"Dùng để thu phục, chuyển hóa người ngoài; Hổ Bào sau khi bị bắt uống xong liền trở thành thành viên bộ lạc Luyện Hồn.","nguon":["@c0508"]},{"id":"khoi-go-den-bo-lac-nho","name":"Khối gỗ đen","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối gỗ màu đen tỏa ánh sáng mờ, tìm được tại nơi tế bái một bộ lạc nhỏ.","detail":"Tộc nhân tấn công một bộ lạc nhỏ rồi tìm được tại nơi tế bái và hiến lên. Vương Lâm chăm chú xem xét nhưng chương chưa tiết lộ công dụng.","nguon":["@c0508"]},{"id":"lenh-bai-dong-thong-linh-co-yeu-thanh","name":"Lệnh bài đồng (Thống lĩnh Cổ Yêu thành)","category":"khac","categoryLabel":"Tín vật","phamCap":"Tín vật chức vị","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài bằng đồng biểu thị chức Thống lĩnh Cổ Yêu thành nắm một vạn yêu binh.","detail":"Tín vật bằng đồng do Vân Lệ Hải (Tả Dực Yêu tương) trao cho Vương Lâm sau khảo nghiệm, xác lập chức Thống lĩnh Cổ Yêu thành thống lĩnh một vạn yêu binh. Theo lời dặn, bảy ngày sau khi nhận lệnh bài sẽ có người dẫn người mang lệnh tới quân doanh.","nguon":["@c0512"]},{"id":"ruou-truc-thanh","name":"Rượu Trúc Thanh","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Rượu ngon","soHuu":[],"trangThai":"dang-co","blurb":"Rượu ngon nổi tiếng Cửu quận của Trúc Thanh lâu, đựng trong vò khổng lồ.","detail":"Loại rượu trứ danh khắp Cửu quận do quán Trúc Thanh lâu trong Cổ Yêu thành cất, chứa trong vò rượu khổng lồ phải bắc thang mới múc được. Quán treo lời thách: uống mười hũ nhỏ mà không say thì được miễn tiền. Vương Lâm uống một ngụm liền nhớ tới loại rượu duy nhất hắn từng uống thời phàm nhân ở Chu Tước Tinh.","nguon":["@c0512"]},{"id":"hon-phien-ho-bao","name":"Hồn phiên (Hổ Bào)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hổ Bào"],"trangThai":"dang-co","blurb":"Pháp bảo của Hổ Bào, khi phất động thả ra vô số hồn phách rít the thé bay đầy tửu lâu.","detail":"Trong hỗn chiến bảo vệ lão tổ, Hổ Bào lấy ra mười lá cờ nhỏ từ trong ngực rồi phất Hồn phiên, thả vô số hồn phách rít lên bay khắp tửu lâu để cản đám yêu binh, song bị sáu đạo Yêu lực phá thần bức lui.","nguon":["@c0513"]},{"id":"ba-qua-cau-ma-niem","name":"Quả cầu ma niệm","cn":"","aliases":["Ba quả cầu đen"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ba quả cầu màu đen kết tụ từ ma niệm bị khu trừ khỏi cơ thể Vương Lâm.","detail":"Sau khi vận tiên lực dò khắp cơ thể suốt hai ngày, Vương Lâm trục xuất hết ma niệm còn sót lại, chúng kết tụ thành ba quả cầu màu đen lơ lửng trước mặt. Hắn cho rằng nếu vận dụng hợp lý, ma niệm có thể ảnh hưởng đạo pháp người khác khiến họ khó lòng phòng bị, nên thu cả ba vào túi trữ vật làm thủ đoạn dùng về sau.","nguon":["@c0514"]},{"id":"hua-yeu-thach","name":"Hứa Yêu thạch","cn":"","aliases":[],"category":"khac","categoryLabel":"Tiền tệ / Vật phẩm","phamCap":"","soHuu":["Thập Tam"],"trangThai":"dang-co","blurb":"Loại thạch dùng làm tiền tệ tại Yêu Linh chi địa.","detail":"Khi rời tửu lâu, Thập Tam để lại chút Hứa Yêu thạch để trả tiền rượu, cho thấy đây là loại thạch dùng làm tiền tệ giao dịch ở vùng đất yêu linh.","nguon":["@c0514"]},{"id":"ngoc-gian-cuu-quan-la-van","name":"Ngọc giản quy tắc Cửu quận (La Vân trao)","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Vương Lâm","Thập Tam"],"trangThai":"dang-co","blurb":"Ngọc giản ghi nội dung quy tắc Cửu quận yêu binh, lấy từ ghi chép tổ tiên do La Vân đưa cho Vương Lâm xem.","detail":"Ngọc giản chứa nội dung về quy tắc Cửu quận yêu binh của Yêu Linh chi địa, vốn dựa trên ghi chép tổ tiên mà La Vân đưa cho Vương Lâm tham khảo. Vương Lâm giao ngọc giản này cho Thập Tam để ghi nhớ nội dung, giúp nắm rõ quân quy và quy định mười người không nghe hiệu lệnh.","nguon":["@c0515"]},{"id":"ngoc-gian-quan-quy-thien-yeu","name":"Ngọc giản quân quy Thiên Yêu quận","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Thập Tam"],"trangThai":"dang-co","blurb":"Ngọc giản ghi quân quy của Thiên Yêu quận với các điều khoản đánh số, được Thập Tam đọc thuộc nội dung.","detail":"Ngọc giản ghi chép hệ thống quân quy Thiên Yêu quận áp dụng trong quân doanh. Thập Tam thuộc nội dung và lần lượt đọc các điều theo lệnh Vương Lâm: điều thứ tám về người dưới xúc phạm cấp trên thì chém, điều thứ mười ba về náo loạn quân doanh và vây khốn cấp trên, điều thứ hai về việc chưa được phép thì không được tự tiện dùng Tru Tiên trận với người bên trong. Vương Lâm dùng chính các điều khoản này làm vũ khí ép chín ngàn yêu binh và Tư Mã Viêm vào thế bị động.","nguon":["@c0516"]},{"id":"huyet-hon-dan","name":"Huyết Hồn đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Diêu Tích Tuyết"],"trangThai":"dang-co","blurb":"Đan dược do phụ thân Diêu Tích Tuyết luyện chế, mỗi viên cho một lần hồi sinh.","detail":"Mỗi viên Huyết Hồn đan tương ứng một lần có thể hồi sinh. Diêu Tích Tuyết đã dùng ba viên trong ba lần xông vào “nơi đó”, dùng thêm khi xông lần thứ tư, hiện còn lại sáu viên; nếu không có đan này nàng đã chết bốn lần.","nguon":["@c0517"]},{"id":"la-ban-do-dieu-tich-tuyet","name":"La bàn màu đỏ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diêu Tích Tuyết"],"trangThai":"dang-co","blurb":"Pháp khí dẫn đường của Diêu Tích Tuyết, dùng mở đường vào vực sâu nơi thủy triều.","detail":"La bàn được Diêu Tích Tuyết dùng để mở đường vào “nơi đó”. Khi giẫm nát, la bàn bung ra vô số phù văn bay lên xoay quanh phòng khoảng ba hơi thở rồi đưa nàng cùng la bàn dịch chuyển biến mất.","nguon":["@c0517"]},{"id":"cay-den-trang-phu-van","name":"Cây đèn trắng khắc phù văn","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diêu Tích Tuyết"],"trangThai":"da-dung","blurb":"Cây đèn trắng khắc phù văn, bóp nát sẽ bay ra giọt máu lam cho pháp thuật tái tạo.","detail":"Phù văn trên đèn thi thoảng lóe sáng như lồng ngực phập phồng. Diêu Tích Tuyết bóp nát đèn để lấy ra giọt máu màu lam, dùng làm cốt lõi cho thuật tái tạo thân thể khi xông vào “nơi đó”.","nguon":["@c0517"]},{"id":"lenh-bai-huyet-phu","name":"Lệnh bài Huyết Phù","category":"khac","categoryLabel":"Khác","phamCap":"Chưa rõ","soHuu":["Diêu Tích Tuyết","Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài Diêu Tích Tuyết định trao để Vương Lâm tự tới Huyết Tổ động phủ lấy tiên ngọc.","detail":"Vật của Diêu Tích Tuyết, cho phép người cầm tự đến động phủ của Huyết Tổ ở Thiên Vận tinh lấy tiên ngọc sau khi ra khỏi Yêu Linh chi địa. Nàng dùng nó cùng cây đèn Huyết Hồn đan và túi tiên ngọc làm thù lao nhờ Vương Lâm giúp bài trừ phong ấn cấm chế trên người mình.","nguon":["@c0519"]},{"id":"bay-pho-tuong-do-dieu-tich-tuyet","name":"Bảy pho tượng đỏ","category":"phap-bao","categoryLabel":"Pháp bảo trận","phamCap":"Thượng cổ","soHuu":["Diêu Tích Tuyết"],"trangThai":"dang-co","blurb":"Bảy pho tượng đỏ như máu ~ba tấc, khắc thú dữ, tỏa mùi tanh; là cốt lõi của trận ẩn thân do Huyết Tổ sáng tạo.","detail":"Mỗi pho tượng cao chừng ba tấc, đỏ như máu, trên thân khắc những con thú dữ lạ và phả ra mùi tanh. Khi thi triển trận ẩn thân, bảy pho tượng bay tới bảy điểm trên mặt đất rồi chui xuống, tạo thành nguồn lực vô hình khiến thần thức kẻ trong trận không soi thấy được chính mình.","nguon":["@c0520"]},{"id":"tien-tinh-vuong-lam","name":"Tiên tinh","category":"khac","categoryLabel":"Thành quả tu luyện","phamCap":"Tự luyện","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tinh thể Vương Lâm cô đọng từ tiên lực theo kết cấu yêu tinh, chứa tiên lực bằng một phần mười số tiên ngọc đã thu.","detail":"Một thứ giống yêu tinh nhưng tỏa ra tiên lực thay vì yêu lực, do Vương Lâm tự luyện bằng cách nén tiên lực hấp thu từ lượng lớn tiên ngọc. Mỗi viên Tiên tinh hàm chứa lượng tiên lực ước bằng một phần mười số tiên ngọc nguyên liệu, giúp hắn tích trữ và vận dụng tiên lực thuận tiện.","nguon":["@c0520"]},{"id":"ngoc-phu-do-dieu-tich-tuyet","name":"Ngọc phù đỏ như máu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diêu Tích Tuyết"],"trangThai":"dang-co","blurb":"Ngọc phù màu đỏ như máu mang thần thông của Diêu Tích Tuyết.","detail":"Cái ngọc phù đỏ như máu của Diêu Tích Tuyết, được Vương Lâm thầm đoán do phụ thân nàng — Huyết Tổ — luyện chế nên mới có thần thông như vậy. Liên hệ với hệ ký tự nét bút ẩn trong các pho tượng đá trên con đường Tôn Long.","nguon":["@c0522"]},{"id":"huyet-ngoc-phong-an","name":"Huyết Ngọc Phong Ấn","cn":"","category":"khac","categoryLabel":"Ngọc phù huyết hệ","phamCap":"","soHuu":["Diêu Tích Tuyết"],"trangThai":"dang-co","blurb":"Ngọc phù do Huyết Tổ tặng Diêu Tích Tuyết, dùng vượt qua tượng đá phong ấn trên các đài đường Tôn Long một cách khéo léo.","detail":"Khác với cách đập vỡ tượng đá ba mắt vốn không làm kim phù bay ra, dùng huyết ngọc phong ấn mới qua được tầng một cách an toàn; Diêu Tích Tuyết từng dùng ba lần trước, vừa qua đài vừa đề phòng Vương Lâm cướp kim phù.","nguon":["@c0523"]},{"id":"huyet-phu-dieu-tich-tuyet","name":"Huyết phù (Diêu Tích Tuyết)","cn":"","aliases":["Ngọc giản huyết sắc","Huyết ngọc trăm năm"],"category":"khac","categoryLabel":"Vật phẩm huyết hệ","phamCap":"","soHuu":["Diêu Tích Tuyết"],"trangThai":"da-dung","blurb":"Loạt ngọc giản huyết sắc và huyết phù mà Diêu Tích Tuyết ném ra để bao phủ, làm ảm đạm rồi tiêu tán kim quang của Vương Lâm.","detail":"Hóa giải kim phù khiến nàng mất một phần mười trữ lượng huyết ngọc trăm năm. Huyết phù chỉ dùng được một lần và đã mất hiệu lực khi chặn đạo kiếm khí thứ hai (Kim Long), khiến nàng vẫn trúng ngực.","nguon":["@c0523"]},{"id":"tui-tru-vat-dieu-tich-tuyet","name":"Túi trữ vật (của Diêu Tích Tuyết)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"bi-cuop","blurb":"Bốn túi trữ vật của Diêu Tích Tuyết — một túi cầm tay và ba túi giấu trong ngực — đều bị Vương Lâm moi ra đoạt sạch sau khi phong ấn nàng.","detail":"Sau khi điểm mi tâm phong ấn Diêu Tích Tuyết, Vương Lâm sờ soạng moi thêm ba túi trữ vật giấu trong ngực nàng rồi đề nghị giao dịch.","nguon":["@c0523"]},{"id":"lo-luyen-dan-dong-phu","name":"Lò luyện đan khổng lồ (động phủ tiên cấm)","category":"khac","categoryLabel":"Pháp khí luyện đan","phamCap":"Không rõ","soHuu":[],"trangThai":"khac","blurb":"Lò luyện đan lớn trong động phủ tiên cấm, nắp có lỗ nhỏ tỏa khói trắng, đáy còn ít nước xanh.","detail":"Một lò luyện đan khổng lồ đặt phía trước dãy lầu các trong động phủ, nắp có lỗ nhỏ vẫn tỏa làn khói trắng, đáy chỉ còn đọng chút nước xanh. Đan dược (nếu có) đã bị người vào trước lấy sạch và cấm chế trên lò cũng đã bị phá.","nguon":["@c0524"]},{"id":"dong-phu-lenh","name":"Động Phủ Lệnh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối lệnh bài bằng thủy tinh cỡ một ngón tay phát sáng bảy màu, là tín vật ra vào động phủ tiên cấm.","detail":"Sau khi Vương Lâm phá cấm chế tiến vào bàn đá, một âm thanh bình thản từ hư vô trao cho hắn tư cách sở hữu động phủ, kèm một đạo tinh quang hóa thành khối Động Phủ Lệnh lơ lửng phát sáng bảy màu. Chỉ cần cầm lệnh bài thì có thể ra vào động phủ, và chừng nào chủ nhân chưa chết thì không ai khác có thể vào được. Vương Lâm dung nhập tâm thần vào lệnh bài để dịch chuyển rời khỏi động phủ.","nguon":["@c0525"]},{"id":"bau-ruou-my-tuu-muoi-giot","name":"Bầu rượu mỹ tửu mười giọt","category":"khac","categoryLabel":"Dị bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bầu rượu nặng bất thường chứa khoảng mười giọt mỹ tửu hương thơm ngát, chỉ một giọt đã đẩy tu vi đại tiến.","detail":"Bầu rượu đặt trên bàn đá trong động phủ, bị cấm chế bảo vệ; Vương Lâm phá cấm bằng kỹ thuật tạo con sóng và vòng nước xoáy rồi luồn tay đoạt lấy. Mở nắp tỏa mùi thơm ngát, bên trong chỉ có khoảng mười giọt mỹ tửu, không phải vật phàm. Uống một giọt khiến toàn thân đỏ bừng, tiên lực điên cuồng lưu chuyển và tăng trưởng, cơn say đẩy hắn vào giấc ngủ dài một năm; tỉnh dậy tu vi đã vượt xa Anh Biến hậu kỳ đại viên mãn. Hắn đánh thêm nhiều đạo cấm chế phong ấn mạnh mẽ rồi cất kỹ chín giọt còn lại.","nguon":["@c0525"]},{"id":"ngoc-phu-huyet-sac","name":"Ngọc phù huyết sắc","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Cực mạnh (cần khẩu quyết để công kích)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hơn một ngàn khối phù bảo huyết sắc trong túi trữ vật thứ hai của Diêu Tích Tuyết, vỡ ra phóng huyết quang phong ấn cực mạnh kèm phòng hộ.","detail":"Mỗi khối Ngọc phù huyết sắc khi vỡ phóng ra huyết quang phong ấn cực mạnh cùng phòng hộ hùng mạnh, và có thể chuyển thành công kích nếu nắm được khẩu quyết hay tâm pháp tương ứng. Vương Lâm hiện chỉ phát huy được tác dụng phòng ngự, để dành khai thác khẩu quyết phong ấn về sau.","nguon":["@c0526"]},{"id":"tieu-lenh-thuy-tinh-dong-phu","name":"Tiểu lệnh thủy tinh","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài thủy tinh chứa khẩu quyết ra vào động phủ Huyết Tổ cùng một tin tức ngắn gọn.","detail":"Vật do động phủ chi linh giao lại trước khi biến mất; trong lệnh bài thủy tinh có khẩu quyết ra vào động phủ và một mẩu tin tức ngắn, được Vương Lâm cầm theo khi rời đi.","nguon":["@c0526"]},{"id":"ba-vo-kiem-vo-danh-chu-tuoc-tinh","name":"Ba vỏ kiếm vô danh Chu Tước Tinh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ba vỏ kiếm Vương Lâm có được ở Chu Tước Tinh, mỗi vỏ phóng ra một đạo kiếm khí mạnh như rồng giận.","detail":"Khi Vương Lâm thả ba vỏ kiếm vô danh, ba đạo kiếm khí mãnh liệt như ba con rồng giận lao ra va chạm yêu khí của hơn mười vạn yêu binh, kết hợp Cấm Phiên hóa khí đen mở đường công phá cung Yêu Tướng.","nguon":["@c0528"]},{"id":"qua-cau-trang-tia-chop-den","name":"Quả cầu trắng tia chớp đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Đệ nhất Đô Thống"],"trangThai":"dang-co","blurb":"Quả cầu nhỏ bằng nắm tay của đệ nhất Đô Thống, bên trong vô số tia chớp đen, dùng chặn Hoàng Tuyền Chỉ.","detail":"Quả cầu màu trắng hình thành giữa hai bàn tay đệ nhất Đô Thống, bên trong vô số tia chớp đen ầm ầm. Nó chặn được Hoàng Tuyền Chỉ của Vương Lâm cách thân ba tấc, song lực không đủ khiến chủ nhân bị đẩy lùi xô sập cửa thứ nhất.","nguon":["@c0528"]},{"id":"tuong-da-thu-hai-phu-van-vang","name":"Tượng đá thứ hai (phù văn màu vàng)","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Bí ẩn","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Phù văn màu vàng Vương Lâm hấp thu từ tượng đá thứ hai, khắc sâu trong đầu, có thể hóa thành lực màu vàng dung nhập phù văn thần thông.","detail":"Các phù văn ký hiệu màu vàng Vương Lâm từng hấp thu từ tượng đá thứ hai khắc sâu trong đầu. Khi giao chiến với Mạc Lệ Hải, phù văn tự dãy dụa muốn thoát ra, càng lúc càng rõ và quấy nhiễu tiên lực; Vương Lâm thuận theo cho nó hóa thành lực màu vàng dung nhập vào ba nét phù văn khí xám, bắn ra thần thông xuyên Yêu Hải. Bí mật của tượng đá chưa được khai thác hết.","nguon":["@c0529"]},{"id":"tui-tru-vat-cu-ma-lao-to","name":"Túi trữ vật của Cự Ma Tộc lão tổ","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chiến lợi phẩm","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Túi trữ vật Vương Lâm thu được sau khi giết Cự Ma Tộc lão tổ ở Chu Tước Tinh, bên trong chứa ba vật quý.","detail":"Vương Lâm thu được túi trữ vật này sau khi giết Cự Ma Tộc lão tổ trong những lần qua lại ở Chu Tước Tinh. Bên trong có bình máu nhỏ của Cổ Thần, một tia nguyên thần của Pháp Cổn Luân và một ngọc giản chưa khai mở.","nguon":["@c0529"]},{"id":"tia-nguyen-than-phap-con-luan","name":"Một tia nguyên thần của Pháp Cổn Luân","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Bí ẩn","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một tia nguyên thần của Pháp Cổn Luân nằm trong túi trữ vật của Cự Ma Tộc lão tổ.","detail":"Một trong ba vật bên trong túi trữ vật Vương Lâm thu được từ Cự Ma Tộc lão tổ; là một tia nguyên thần của Pháp Cổn Luân, nội dung và lai lịch chưa được khai mở.","nguon":["@c0529"]},{"id":"ngoc-gian-cu-ma-lao-to","name":"Ngọc giản (Cự Ma Tộc lão tổ)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Bí ẩn","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chưa khai mở nằm trong túi trữ vật của Cự Ma Tộc lão tổ.","detail":"Một trong ba vật bên trong túi trữ vật Vương Lâm thu được từ Cự Ma Tộc lão tổ; nội dung ngọc giản chưa được khai mở, cài cắm thông tin hoặc công pháp cho về sau.","nguon":["@c0529"]},{"id":"hon-phien-bo-lac-luyen-hon","name":"Hồn phiên (bộ lạc Luyện Hồn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo bộ lạc","soHuu":["Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Cây phiên của bộ lạc Luyện Hồn, hồn phách bay ra vào dung nhập hắc vụ trên bầu trời, tộc nhân tu luyện quanh đó.","detail":"Pháp bảo trung tâm của bộ lạc Luyện Hồn ngoài Cổ Yêu thành. Hồn phách bay ra vào dung nhập màn hắc vụ bao phủ trên bầu trời, tộc nhân tu hành quanh hồn phiên; bộ lạc có mấy trăm người thủ hộ.","nguon":["@c0529"]},{"id":"bo-ao-giap-co-hac-thap","name":"Bộ áo giáp cổ (trong hắc tháp)","category":"phap-bao","categoryLabel":"Vật cổ / Pháp bảo","phamCap":"Vật cổ xưa bí ẩn","soHuu":["Chủ nhân (bộ áo giáp trong hắc tháp)"],"trangThai":"dang-co","blurb":"Bộ áo giáp cực kỳ cổ xưa, đen bóng, đồ án hình mây đen quỷ dị, đặt ở tầng cao nhất hắc tháp; mũ giáp lóe u quang như ánh mắt, là chỗ ngụ của chủ nhân.","detail":"Bộ áo giáp được bảo tồn hoàn chỉnh, bề mặt đen bóng phủ đồ án hình mây đen quỷ dị, nhìn từ xa như có người mặc giáp ngồi khoanh chân. Mũ giáp lóe hai đạo u quang như ánh mắt, khiến trời đất rung lên như có tiên linh hàng lâm; khí kỳ dị tỏa ra bao phủ cả tòa hắc tháp mười tầng. Đây là nơi ngụ của thực thể cổ xưa được gọi là chủ nhân, vừa thức tỉnh chưa lâu.","nguon":["@c0530"]},{"id":"ngoc-gian-mau-xanh-cu-linh-cuu-tu","name":"Ngọc giản màu xanh (Cự Linh Cửu Tu)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Ngọc giản chứa công pháp","soHuu":["Vương Lâm","Thập Tam"],"trangThai":"dang-co","blurb":"Ngọc giản màu xanh Vương Lâm dùng chép sáu tầng đầu Cự Linh Cửu Tu để truyền cho Thập Tam.","detail":"Ngọc giản màu xanh được Vương Lâm dùng để chép lại sáu tầng đầu của bộ công pháp luyện thể Cự Linh Cửu Tu (sau khi xóa ba tầng cuối), rồi ném cho Thập Tam như truyền thừa.","nguon":["@c0530"]},{"id":"ngoc-gian-luyen-hon-thuat-phan-hai","name":"Ngọc giản phần hai Luyện Hồn Thuật","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm","Âu Dương Hoa"],"trangThai":"dang-co","blurb":"Ngọc giản chứa phần thứ hai của Luyện Hồn Thuật — thần thông rút phách, chỉ truyền cho chi chính bộ lạc Luyện Hồn.","detail":"Vương Lâm trao cho Âu Dương Hoa trước khi rời sơn cốc, dặn chỉ truyền cho chi chính. Âu Dương Hoa bóp nát ngọc giản sau khi ghi nhớ toàn bộ pháp môn rút phách bên trong.","nguon":["@c0531"]},{"id":"truyen-tong-tran-thu-muoi-bon","name":"Truyền tống trận thứ mười bốn","category":"khac","categoryLabel":"Trận pháp","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Một trong mười tám truyền tống trận ngoài Thiên Yêu thành, chuyên dụng đưa Yêu tướng các nơi vào kinh.","detail":"Ngoài Thiên Yêu thành đặt mười tám truyền tống trận: tám tòa cho dân chúng và thương nhân, mười tòa cho người có chức vụ. Trong số đó, trận thứ mười bốn dành riêng cho Yêu tướng vào kinh, có Yêu binh trấn thủ quanh năm. Khi kích hoạt, trận phóng ra quầng sáng và yêu lực khổng lồ; Mạc Lệ Hải cùng Vương Lâm đã từ trận này bước ra Đế Đô.","nguon":["@c0532"]},{"id":"tuy-binh-dan","name":"Tuy Bình đan dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Trần Đào"],"trangThai":"dang-co","blurb":"Một túi đan dược Vương Lâm tặng Trần Đào để biểu thị thiện chí, vô tác dụng với thương thế.","detail":"Vương Lâm lấy ra một túi Tuy Bình đan ném cho Trần Đào trên quân đạo. Đan này vô dụng với thương thế nặng của Trần Đào, chỉ mang ý nghĩa biểu thị thiện chí và ngầm gợi ý liên kết đồng môn đối phó Đại La Kiếm Tông.","nguon":["@c0533"]},{"id":"thien-nguyen-dan","name":"Thiên Nguyên đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Trần Đào"],"trangThai":"","blurb":"Đan dược Trần Đào dự định luyện nếu đủ tài liệu, có thể ngắn hạn khôi phục tu vi về Vấn Đỉnh sơ kỳ.","detail":"Trần Đào nói nếu thu thập đủ tài liệu thì có thể luyện một lò Thiên Nguyên đan, giúp hắn trong ngắn hạn khôi phục tu vi từ Anh Biến viên mãn lên lại Vấn Đỉnh sơ kỳ. Thạch Tiễn hứa đã phái người đi thu thập tài liệu — nếu thành công sẽ thay đổi cục diện cuộc chiến Yêu tướng.","nguon":["@c0533"]},{"id":"yeu-giap-mac-le-hai","name":"Yêu giáp (của Mạc Lệ Hải)","cn":"","category":"khac","categoryLabel":"Yêu giáp","phamCap":"","soHuu":["Mạc Lực Hải"],"trangThai":"dang-co","blurb":"Tầng yêu lực bảo hộ thân thể Mạc Lệ Hải; bị năm đạo sát lục khí của Vương Lâm len qua quyền phong chấn động kịch liệt.","detail":"Lớp yêu giáp do yêu lực kết thành bảo hộ thân thể Mạc Lệ Hải. Trong lúc thử sức với Vương Lâm, năm con thương long sát lục khí dung hợp len qua quyền phong đánh tới ngực, tuy bị tầng yêu lực bật lại nhưng vẫn làm yêu giáp chấn động kịch liệt, khiến Mạc Lệ Hải kinh ngạc trước sự sắc bén của thứ khí xám.","nguon":["@c0535"]},{"id":"dan-minh-huyen","name":"Cây đàn của Minh Huyên","cn":"","category":"khac","categoryLabel":"Nhạc cụ","phamCap":"","soHuu":["Minh Huyên"],"trangThai":"dang-co","blurb":"Cây đàn Minh Huyên dùng trên hoa thuyền để truyền nỗi bi thương; tiếng đàn xuyên cả phong ấn trí nhớ của Vương Lâm.","detail":"Minh Huyên dùng cây đàn này gảy lên những khúc nhạc bi thương trên hoa thuyền qua lại bờ sông Hồng thành. Tiếng đàn thấm đẫm nỗi buồn, khiến Vương Lâm ngồi nghe ba ngày liền để tẩy rửa tâm linh và có cảm ngộ mới về đạo nghịch thiên.","nguon":["@c0535"]},{"id":"yeu-kiem-yeu-de-ngan-long","name":"Yêu kiếm của yêu đế","aliases":["Ngân long","Ác long bạc"],"category":"phap-bao","categoryLabel":"Pháp bảo (kiếm)","phamCap":"Trọng bảo của yêu đế","soHuu":["Yêu đế"],"trangThai":"dang-co","blurb":"Yêu kiếm của yêu đế, hiện thân dạng ác long màu bạc trên bầu trời thế giới máu, hút huyết sát vụ làm thức ăn.","detail":"Tại thế giới máu tầng đáy Hồng lao, khi sát vụ trên người tu sĩ đủ dày, một con ác long màu bạc — chính là yêu kiếm của đế quân — hiện ra giữa bầu trời, đôi mắt lạnh như băng, hút mạnh huyết sát vụ để nuôi dưỡng. Kẻ nào dám lao tới phản kháng liền bị xé tan, rồi sống lại từ một hồ máu khác thành kẻ bình thường. Cả thế giới máu tầng đáy do đế quân tự chế tạo chính là nơi tích lũy sát lục khí nuôi thanh yêu kiếm này.","nguon":["@c0536"]},{"id":"de-kiem-ngan-long","name":"Đế Kiếm","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Thanh kiếm hình con rắn cắm giữa trận pháp huyết sắc ở Kiếm Các, hóa thành ngân long trong thế giới huyết sắc; tự xưng Đế Quân Chi Kiếm.","detail":"Còn gọi là Đế Quân Chi Kiếm hay ngân long. Là thanh kiếm hình rắn cắm giữa trận pháp huyết sắc ở Kiếm Các trong hoàng cung Đế Đô. Trong thế giới huyết sắc hóa thành ngân long, hấp thu sát vụ chuyển thành sinh cơ, tôn nghiêm bất khả xâm phạm. Bị Vương Lâm dùng 3792 đạo sát lục khí đánh bại một trảo nên phẫn nộ, tự rút khỏi trận nhãn bay về Hồng Thành, lùng sục Thiên Yêu Thành cả tháng và phá Hồng Lao mười lần (chém rãnh dài nghìn trượng) mà không tìm ra Vương Lâm.","nguon":["@c0537","@c0544"]},{"id":"bau-ruou-nhat-vuong-lam","name":"Bầu rượu nhạt","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bầu rượu Vương Lâm cầm khi ngồi nghe đàn bên sông, thi thoảng uống một ngụm.","detail":"Bầu rượu nhạt Vương Lâm cầm khi ngồi bên sông nghe tiếng đàn của họa thuyền, thi thoảng uống một ngụm; dùng để nâng rượu chào thanh niên áo xanh từ xa.","nguon":["@c0537"]},{"id":"de-kiem-de-do-kiem-cac","name":"Đế Kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Người mặc hoàng bào (Đế Đô Kiếm Các)"],"trangThai":"dang-co","blurb":"Ngân kiếm có linh tính kiêu ngạo, đặt chính giữa trận pháp Đế Đô Kiếm Các, hay tới Hồng Lao phá hoại.","detail":"Kiếm bạc đặt chính giữa trận pháp Đế Đô Kiếm Các, có linh tính kiêu ngạo, hay tới Hồng Lao phá hoại. Bị người mặc hoàng bào trấn áp trong trận pháp, cấm tới Hồng Lao và bị dọa đưa tới Long Đàm. Đế Kiếm bất lực ngừng kêu nhưng vẫn tức giận con mồi dám khiêu khích.","nguon":["@c0538"]},{"id":"ruou-quy-chon-nam-tram-nam-mac-le-hai","name":"Rượu quý chôn hơn năm trăm năm","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Mạc Lệ Hải"],"trangThai":"da-dung","blurb":"Rượu quý Mạc Lệ Hải chôn hơn năm trăm năm, mời Vương Lâm uống mừng.","detail":"Rượu quý mà Mạc Lệ Hải đã chôn hơn năm trăm năm, đem ra mời Vương Lâm uống mừng sau khi nhờ cậy hắn trợ giúp đại hội Yêu Tướng.","nguon":["@c0538"]},{"id":"phi-kiem-ran-nuoc-nguoi-ao-den","name":"Phi kiếm rắn nước (của người áo đen)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Người áo đen (sát thủ thám thính)"],"trangThai":"hong","blurb":"Phi kiếm mảnh như rắn nước quấn thân sát thủ Yêu Linh, vỡ tan khi chạm hắc khí Tịch Diệt Chỉ.","detail":"Phi kiếm mảnh như rắn nước quấn quanh thân người áo đen; khi chạm vào đạo hắc khí của Tịch Diệt Chỉ thì vỡ tan như chẻ tre.","nguon":["@c0539"]},{"id":"trong-thien-yeu","name":"Trống Thiên Yêu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Trống trận đen kịt đặt giữa quảng trường Đế Đô Thiên Yêu.","detail":"Trống đen kịt toát ra khí tang thương, đặt giữa quảng trường vạn trượng ở Đế Đô. Chỉ vang khi tế tổ (sáu tiếng), mở Long Đàm (chín tiếng) hoặc khi có sự kiện trọng đại (ba tiếng); âm thanh chấn động cả Thiên Yêu Thành.","nguon":["@c0543"]},{"id":"pho-thien-trieu-ky","name":"Phó Thiên Triệu Kỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Huyền Phó Soái"],"trangThai":"dang-co","blurb":"Bảo vật Huyền Phó Soái đặt cược về thành tích Vương Lâm.","detail":"Bảo vật của Huyền Phó Soái, sẽ giao cho Hoàng Phó Soái nếu Vương Lâm không dẫn đầu trận chiến Yêu Tướng.","nguon":["@c0543"]},{"id":"huyen-huyen-dan","name":"Huyền Huyền Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Hoàng Phó Soái"],"trangThai":"dang-co","blurb":"Đan dược Hoàng Phó Soái đặt cược về thành tích Vương Lâm.","detail":"Đan dược của Hoàng Phó Soái, sẽ giao cho Huyền Phó Soái nếu Vương Lâm đứng đầu trận chiến Yêu Tướng.","nguon":["@c0543"]},{"id":"truong-thuong-vang-kim-tong-quan","name":"Trường thương màu vàng (Kim tổng quản)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam tử mặc giáp vàng"],"trangThai":"dang-co","blurb":"Trường thương Kim tổng quản ngưng từ ánh sáng mặt trời, uy lực như khai thiên lập địa.","detail":"Kim tổng quản ngưng kim quang và ánh sáng mặt trời hóa thành cây trường thương màu vàng, uy lực như khai thiên lập địa, có thể phong tỏa đối thủ. Hắn phóng vào Vương Lâm để cứu Ngao Địch, nhưng bị Vương Lâm dùng Sinh Chi Lạc Ấn vỗ hai cái làm đổi hướng; sau đó trường thương hóa thành tia sáng mặt trời biến mất.","nguon":["@c0544"]},{"id":"thien-yeu-dan","name":"Thiên Yêu Đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cực phẩm","soHuu":["Yêu Đế"],"trangThai":"dang-co","blurb":"Đan dược cực trân quý của Yêu Đế, đủ sức cứu một phế nhân.","detail":"Thiên Yêu Đan là đan dược cực kỳ trân quý do Yêu Đế ban, có thể cứu cả phế nhân. Ngay cả Yêu Soái lập vô số chiến công mới có cơ hội nhận được. Sau khi Ngao Địch bị Vương Lâm đánh thành phế nhân, chỉ có Thiên Yêu Đan mới phục hồi nổi hắn.","nguon":["@c0544"]},{"id":"bon-menh-long-quy-ngao-dich","name":"Bổn mệnh yêu thú long quy (Ngao Địch)","category":"khac","categoryLabel":"Yêu thú","phamCap":"","soHuu":["Ngao Địch"],"trangThai":"dang-co","blurb":"Bổn mệnh yêu thú long quy của Ngao Địch, máu tươi hóa hư ảnh nuốt đối thủ.","detail":"Bổn mệnh yêu thú long quy của Yêu Tướng Ngao Địch. Khi bị Vương Lâm dồn ép, Ngao Địch cắn lưỡi phun máu tươi hóa thành hư ảnh long quy lao tới nuốt Vương Lâm, nhưng tia máu bị tầng tầng Sinh Chi Lạc Ấn vô hình của Vương Lâm hóa giải tới tầng thứ tám.","nguon":["@c0544"]},{"id":"de-kiem-kiem-cac-de-do","name":"Đế Kiếm (Kiếm Các Đế Đô)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Đế Quân"],"trangThai":"dang-co","blurb":"Kiếm Linh hình con rắn tại Kiếm Các trong Đế Đô, kiếm thể có thể hóa thành thiếu nữ; thuộc về Đế Quân.","detail":"Đế Kiếm là thanh kiếm chứa Kiếm Linh đặt ở Kiếm Các trong Đế Đô, hình con rắn, có thể hóa thành thiếu nữ. Chính là “tiểu mỹ nhân” mà Hứa Lập Quốc si mê. Thiếu nữ Kiếm Linh hung tợn thề rằng nếu thấy “Kiếm Linh vô sỉ kia” (Hứa Lập Quốc) sẽ trái lệnh Đế Quân lao ra chém.","nguon":["@c0545"]},{"id":"cu-kiem-tim-mat-duong","name":"Cự kiếm tím (bảo kiếm bản mệnh Mạt Dương)","cn":"","aliases":["Tà Dương Chi Hồn","Dương Hồn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Mạt Dương"],"trangThai":"mat","blurb":"Cự kiếm màu tím kiếm khí nồng đậm, hoa văn biến ra hư ảnh con dê tím Tà Dương Chi Hồn hợp nhất tăng uy lực.","detail":"Bảo kiếm bản mệnh của Mạt Dương: cự kiếm màu tím, kiếm khí nồng đậm, trên thân có hoa văn kỳ dị biến ra hư ảnh con dê tím (Tà Dương Chi Hồn / Dương Hồn) khí bạo ngược, hợp nhất với kiếm để tăng uy lực. Trong trận với Vương Lâm, kiếm bị bắt sống bằng tay phải ngàn dấu ấn, Dương Hồn bị sát lục chi khí đánh tan rồi kiếm được trả lại; mất kiếm bản mệnh khiến Mạt Dương hộc máu, tâm thần hao tổn.","nguon":["@c0541"]},{"id":"chien-thu-mac-phi","name":"Chiến thư của Mặc Phi","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Mặc Phi","Mạt Dương"],"trangThai":"dang-co","blurb":"Bức thư màu vàng kim quang chỉ có một chữ “Chiến!”, hẹn quyết chiến ba ngày sau ngoài sảnh đường Cổ Đạo.","detail":"Chiến thư Mặc Phi sai Mạt Dương đưa tới Mạc Lệ Hải: bức thư màu vàng tỏa kim quang, trên chỉ viết một chữ “Chiến!”, định mốc quyết chiến ba ngày sau bên ngoài sảnh đường Cổ Đạo.","nguon":["@c0541"]},{"id":"chien-yeu-co","name":"Chiến Yêu Cổ","cn":"","aliases":["Yêu Cổ"],"category":"khac","categoryLabel":"Thánh vật","phamCap":"Thánh vật Thiên Yêu Quận","soHuu":["Thiên Yêu Quận"],"trangThai":"dang-co","blurb":"Thánh vật Thiên Yêu Quận làm từ da Cổ Yêu, gõ ra số tiếng vang đo thực lực; người huyết khí không đủ gõ không vang còn tự sụp đổ.","detail":"Thánh vật của Thiên Yêu Quận, được nói gần giống Long Đàm, làm từ da Cổ Yêu và lưu lại từ đời Đế Quân thứ nhất. Người huyết khí không đủ không gõ vang nổi mà còn tự sụp đổ; mỗi tiếng phản chấn càng mạnh. Gõ được ba tiếng là cường giả, sáu tiếng là Thiên Kiêu; Thiên Soái từng gõ được mười lăm tiếng (kỷ lục). Ở vòng hai cuộc tranh đoạt Yêu Tướng, tiếng trống lan tới nửa Thiên Yêu thành; Vu Sâm gõ bốn tiếng, Mặc Phi gõ tám tiếng.","nguon":["@c0546"]},{"id":"tinh-the-guong-mac-phi","name":"Tinh thể phẳng như gương","category":"khac","categoryLabel":"Pháp khí phòng ngự","phamCap":"","soHuu":["Mặc Phi"],"trangThai":"dang-co","blurb":"Mặc Phi bắt quyết tạo từ bạch quang để đỡ và giảm nửa phản lực tiếng trống thứ tám.","detail":"Vật phòng ngự mà Mặc Phi bắt quyết tạo ra từ bạch quang, phẳng như gương, dùng để đỡ và giảm bớt một nửa phản lực khi gõ Chiến Yêu Cổ tiếng thứ tám. Dù vậy hắn vẫn bị chấn lùi hơn trăm trượng.","nguon":["@c0546"]},{"id":"yeu-co","name":"Yêu Cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Khảo nghiệm","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc trống đen làm từ da cổ yêu, đánh càng nhiều phản chấn càng mạnh; khảo nghiệm cao nhất trong các vòng đấu.","detail":"Mặt trống có vân nhỏ như da thú, ẩn tinh khí. Đánh càng nhiều phản chấn càng mạnh — tiếng thứ chín phá vỡ ba nghìn bảy trăm Lạc Ấn Sinh Mệnh. Phản lực là khí tức bất khuất, cuồng ngạo nghịch thiên trong ý niệm. Là khảo nghiệm cao nhất trong các vòng đấu của Thiên Yêu Thành. Kỷ lục cũ tám tiếng do đệ nhất yêu tướng Mặc Phi nắm giữ, bị Vương Lâm vượt qua với chín tiếng.","nguon":["@c0547","@c0548"]},{"id":"yeu-co-trong-truyen-thua","name":"Yêu Cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Khí cụ truyền thừa","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Trống truyền thừa của Thiên Yêu quận, làm bằng da Cổ Yêu, dùng để gõ rút sức mạnh Cổ Yêu tẩy tủy.","detail":"Yêu Cổ ở Thiên Yêu quận chỉ xếp sau sinh vật trong Long Đàm về địa vị. Trống làm bằng da Cổ Yêu, hàm chứa lực lượng Cổ Yêu. Các triều Yêu Đế dùng phương pháp truyền thừa gõ trống để rút sức mạnh Cổ Yêu, bảo vệ Thiên Yêu quận vạn vạn năm vinh quang. Dùng để tẩy tủy — chỉ Đế tộc đủ tư cách, người ngoài phải lập công lớn mới được ban thưởng; mỗi Yêu Soái trước khi nhận chức được ban một lần gõ trống, thành bại tùy tu vi.","nguon":["@c0549"]},{"id":"lo-dinh-an-du","name":"Lô Đỉnh (ẩn dụ)","cn":"","category":"khac","categoryLabel":"Ẩn dụ / khái niệm","phamCap":"","soHuu":[],"trangThai":"","blurb":"Ẩn dụ về việc lợi dụng người mình yêu để tu hành; Vương Lâm lo nếu xóa bỏ hình bóng Uyển Nhi thì nàng vô tình trở thành Lô Đỉnh của hắn.","detail":"Khi đứng trước Yêu Cổ, Vương Lâm nhận ra rằng quét sạch bi thương để lên Vấn Đỉnh đồng nghĩa xóa bỏ hình bóng Lý Mộ Uyển, biến nàng thành “Lô Đỉnh” — dùng người mình yêu làm công cụ tu hành. Hắn từ chối làm vậy, chọn giữ trọn tình cảm.","nguon":["@c0550"]},{"id":"ky-khoi-phach-kim-o-huc","name":"Kỳ Khôi Phách","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Kim Ô Húc"],"trangThai":"hong","blurb":"Vật phòng thân của Kim Ô Húc; bị lực phản chấn tiếng trống thứ mười lăm đánh vỡ cùng cái chết của hắn.","detail":"Kỳ Khôi Phách là pháp bảo hộ thân của Kim Ô Húc (Kim tổng quản) ở Thiên Yêu quận. Khi tiếng trống thứ mười lăm của Yêu Cổ giáng lực phản chấn lên thân hắn, không chỉ thân thể nát vụn tiêu tán mà đến Kỳ Khôi Phách cũng bị đánh vỡ, mọi dấu vết biến mất.","nguon":["@c0551"]},{"id":"nguyen-nguyen-tao-hoa-dan","name":"Nguyên Nguyên Tạo Hóa Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Đan dược Lăng Thiên Hậu đang luyện bên lò khổng lồ trong Đại La Kiếm Tông.","detail":"Lăng Thiên Hậu luyện chế Nguyên Nguyên Tạo Hóa Đan bên một lò luyện đan khổng lồ trong Đại La Kiếm Tông, định kiếm thêm vài dược liệu phụ thì cảm ứng thiên kiếp giáng lâm.","nguon":["@c0552"]},{"id":"yeu-co-thanh-vat","name":"Yêu Cổ","cn":"","category":"khac","categoryLabel":"Thánh vật","phamCap":"Thánh vật","soHuu":[],"trangThai":"dang-co","blurb":"Thánh vật của Thiên Yêu quận, vật duy nhất không bị thiên uy ép hóa thành bụi phấn khi cả Đế Đô Thiên Yêu thành bị hủy.","detail":"Yêu Cổ là thánh vật của Thiên Yêu quận / Đế Đô Thiên Yêu thành. Khi thiên kiếp Vương Lâm nghiền nát cả tòa thành vạn năm thành tro bụi, Yêu Cổ là vật duy nhất không bị thiên uy ép hóa thành bụi phấn. Tên chương đặt theo vật này, có khả năng liên quan đến giọng nói âm u tự xưng Cổ Yêu.","nguon":["@c0554"]},{"id":"van-dinh-chi-tinh-chu-dat","name":"Vấn Đỉnh Chi Tinh (của Chu Dật)","category":"phap-bao","categoryLabel":"Trái tim nguyên thần","phamCap":"Vấn Đỉnh Chi Tinh","soHuu":["Chu Dật","Vương Lâm"],"trangThai":"da-dung","blurb":"Viên ngọc hồng to bằng ngón tay tỏa thiên đạo chi uy, do Chu Dật tặng Vương Lâm.","detail":"Vấn Đỉnh Chi Tinh là trái tim nguyên thần của người tiến Vấn Đỉnh, mang Ý cảnh Chí Tử Si Ý. Khi rút ra khiến tiên khí xung quanh ngừng vận chuyển. Vương Lâm nuốt vào trong lúc tiến Vấn Đỉnh; lúc hắn suýt thất bại, viên ngọc tự bay vào kén nguyên thần, dập bớt tiên hỏa, bay một vòng quanh Vấn Đỉnh Chi Tinh của Vương Lâm rồi tan vỡ, dồn toàn bộ nguyên khí khiến viên của Vương Lâm tăng từ móng tay thành ngón tay, trở thành ‘trái tim thứ hai’ của hắn.","nguon":["@c0555"]},{"id":"lenh-bai-than-bi-dong-phu","name":"Lệnh bài thần bí động phủ","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài cho phép Vương Lâm tùy ý tiến vào thần bí động phủ bất cứ lúc nào.","detail":"Khắc khẩu quyết ấn ký; khi dùng, lóe bạch quang bao phủ rồi dịch chuyển vào thần bí động phủ. Vương Lâm dùng sau thiên kiếp để vào nơi an toàn nhất luyện Vấn Đỉnh.","nguon":["@c0555"]},{"id":"xich-tieu-van-mang","name":"Xích Tiêu Vân Mang","category":"khac","categoryLabel":"Thiên kiếp / hồng quang","phamCap":"Thiên kiếp tối hậu","soHuu":[],"trangThai":"da-dung","blurb":"Đạo hồng quang rộng hơn mười trượng mạnh hơn hồng lôi trước rất nhiều cấp, đòn thiên kiếp cuối.","detail":"Sau khi hồng vân tan, Xích Tiêu Vân Mang giáng xuống nhắm vào hư ảnh Cổ Yêu. Cổ Yêu há miệng nuốt; cơ thể tan vỡ - tổ hợp một vạn lần trong vài hơi thở rồi bị ép đạp đất, sóng tròn cao ba trượng lan trăm vạn dặm. Sau khi nuốt xong, hồng vân hoàn toàn tiêu tán.","nguon":["@c0555"]},{"id":"ao-giap-hac-thap-556","name":"Áo giáp trong hắc tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"dang-co","blurb":"Chiếc giáp đặt ở tầng cao nhất hắc tháp, có hai đạo u quang, là nơi trú của một tồn tại bị thương nặng.","detail":"Áo giáp ngụ ở tầng cao nhất của hắc tháp trên chiến trường viễn cổ Thiên Yêu quận; trong giáp lóe hai đạo u quang, có thể quét thần thức tàn bạo khắp chiến trường, điều khiển vô số khúc xương đen và mở vòng xoáy không gian. Vì chủ nhân bị thương quá nặng nên giáp tự phá bỏ một cánh tay để đi đoạt nguyên khí tu sĩ Vấn Đỉnh; sau khi cánh tay phóng đi, áo giáp mất một cánh tay và u quang tắt hẳn.","nguon":["@c0556"]},{"id":"ho-uyen-lua-ma-556","name":"Hộ uyển lửa ma","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"dang-co","blurb":"Hộ uyển bằng sắt đen tỏa lửa ma dày đặc, dính chặt vào bộ xương cánh tay đen để ngưng tụ ma lực khổng lồ.","detail":"Một hộ uyển (vòng/giáp tay) bằng sắt đen tỏa lửa ma dày đặc rơi ra từ bộ giáp trong hắc tháp, bay tới dính chặt vào khớp của bộ xương cánh tay đen. Lửa ma khiến ma lực khổng lồ ngưng tụ điên cuồng, biến cánh tay xương thành công cụ trảo đoạt nguyên khí của Vương Lâm.","nguon":["@c0556"]},{"id":"bo-xuong-canh-tay-den-556","name":"Bộ xương cánh tay màu đen","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"dang-co","blurb":"Cánh tay xương đen ngưng từ vô số khúc xương trên chiến trường viễn cổ, kết hợp hộ uyển lửa ma để đoạt nguyên khí.","detail":"Vô số khúc xương đen trên chiến trường viễn cổ Thiên Yêu quận bay lên dung hợp thành một bộ xương cánh tay màu đen. Kết hợp với hộ uyển lửa ma, cánh tay xương được phóng qua vòng xoáy đen chộp xuống Vương Lâm để đoạt nguyên khí; bị né hụt thì lùi về vòng xoáy rồi tiếp tục đuổi theo.","nguon":["@c0556"]},{"id":"thang-tien-qua","name":"Thăng Tiên Quả","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Tiên quả màu đỏ bằng nắm tay trẻ sơ sinh, mùi hương quỷ dị; ăn vào gây hưng phấn lâng lâng như thành thần tiên.","detail":"Quả màu đỏ bằng nắm tay trẻ sơ sinh, mùi thơm quỷ dị, ăn vào gây hưng phấn lâng lâng như thành thần tiên; tác dụng lớn với phàm nhân, nhỏ với tu sĩ, được người quyền quý phàm nhân bỏ tiền lớn mua. Trên Chu Tước Tinh cũng có nhưng số lượng ít. Một khu vườn Yêu Linh trồng không dưới một vạn cây. Vương Lâm thu hơn một vạn quả, hai tay hợp lại làm vạn quả vỡ vụn cô đọng còn một giọt đỏ như máu, nuốt để lấy kích thích cực mạnh (hưng phấn + đau đớn + khoái cảm) làm động lực ép xuất hắc ảnh Thiên Ma Loạn Vũ.","nguon":["@c0557"]},{"id":"ho-uyen-bo-xuong-canh-tay-den","name":"Hộ uyển (bộ xương cánh tay đen)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Chủ nhân hộ uyển (kẻ trong hắc tháp)","Vương Lâm"],"trangThai":"bi-cuop","blurb":"Hộ uyển bọc ngoài bộ xương cánh tay màu đen, tản ma khí gần thành thực chất, mang ký hiệu dựng nhà lao ma lực giam không gian.","detail":"Bọc ngoài bộ xương cánh tay màu đen, tản ma khí gần thành thực chất; hấp thụ được khí tịch diệt của Tịch Diệt Chỉ; va tiên kiếm phát tiếng két két như băng chụp sắt. Ký hiệu trên hộ uyển kích hoạt khiến tro bộ xương khuếch tán thành vầng sáng hắc sắc nghìn trượng tạo nhà lao ma lực giam không gian, phát ma âm keng keng chói tai và sinh hắc ảnh một sừng Thiên Ma Loạn Vũ. Cuối chương bị Vương Lâm chụp lấy, phun khí nguyên thần hóa cấm chế hình mạng nhện phong ấn rồi cất vào túi trữ vật.","nguon":["@c0557"]},{"id":"kiem-linh-tu-thu","name":"Kiếm Linh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tử Thử"],"trangThai":"mat","blurb":"Linh thể kiếm mà Tử Thử nuôi dưỡng, hắn muốn dùng nguyên thần Vấn Đỉnh của Vương Lâm để tăng mạnh uy lực.","detail":"Kiếm Linh là vật Tử Thử dày công nuôi dưỡng. Biết cơ hội gặp một người Vấn Đỉnh trọng thương là hiếm có, Tử Thử tham lam muốn đoạt nguyên thần Vấn Đỉnh của Vương Lâm để dưỡng mạnh Kiếm Linh, song chính vì lòng tham này mà hắn liều mạng tấn công và bị giết trong nháy mắt.","nguon":["@c0559"]},{"id":"dai-kiem-tu-thu","name":"Đại kiếm của Tử Thử","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tử Thử"],"trangThai":"mat","blurb":"Đại kiếm đeo sau lưng Tử Thử, bay ra khi hắn bắt pháp quyết.","detail":"Khi Tử Thử hai tay bắt pháp quyết để nghênh chiến, đại kiếm sau lưng hắn bay ra. Nhưng Vương Lâm hiện thân quá nhanh, tay phải chụp lấy thanh kiếm ném ra phía sau khiến đòn tấn công của Tử Thử trở nên vô dụng.","nguon":["@c0559"]},{"id":"dao-kiem-khi-su-ton-tu-thu","name":"Đạo kiếm khí của sư tôn (tặng Tử Thử)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tử Thử"],"trangThai":"mat","blurb":"Một đạo kim quang kiếm khí do sư tôn tặng, lưu ở mi tâm Tử Thử nhưng chưa kịp dùng thì hắn đã chết.","detail":"Sau khi Tử Thử chết, xác khô héo rơi xuống đất, trên mi tâm còn một đạo kim quang lấp lánh — đạo kiếm khí mà sư tôn tặng. Tử Thử chưa kịp sử dụng đạo kiếm khí này thì đã bị Vương Lâm giết, cho thấy chênh lệch giữa hai bên quá lớn.","nguon":["@c0559"]},{"id":"sao-tieu-giap","name":"Sáo Tiêu giáp","cn":"","aliases":["Áo giáp trong hắc tháp"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"dang-co","blurb":"Bộ giáp của lão giả hắc giáp, tự mang đạo của mình và là nguồn các thần thông Phong/Vũ/Lôi/Điện.","detail":"Bộ giáp khoác trên người lão giả hắc giáp bước ra từ hắc tháp. Lão tự nhận mình không có đạo, nhưng bộ Sáo Tiêu giáp này lại có đạo của riêng nó. Giáp nâng biểu hiện tu vi lão lên tới Vấn Đỉnh hậu kỳ (cao hơn tu vi chân thật) và ban cho lão các thần thông hệ phong–lôi: Phong, Vũ, Lôi, Điện, có thể gộp lại buông xuống đại địa.","nguon":["@c0563"]},{"id":"hac-thap-vien-co-pham-bao","name":"Hắc tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"dang-co","blurb":"Tòa tháp đen cực kỳ quan trọng với ma phó; là nguồn ma khí biến hắc giáp lão giả thành ma nhân khổng lồ.","detail":"Hắc tháp được mô tả là cực kỳ quan trọng với ma phó. Bên trong tháp phát ra tiếng hừ lạnh phòng ngự; khi tia kim mang kiếm khí của Lăng Thiên Hậu lao tới, tháp bị đánh chấn động và nứt một vết nhưng không sụp. Sau đó một cỗ ma khí nồng đậm từ hắc tháp nhập vào hắc giáp lão giả khiến thân hắn phồng lên thành người khổng lồ cao ba trượng, bạch giáp biến lớn, một hắc giác mọc từ trán — không còn là người. Lão giả hiểu rõ tầm quan trọng của tháp nên bỏ truy kích Vương Lâm để cứu tháp.","nguon":["@c0564"]},{"id":"liem-dao-ma-dao-hac-giap-lao-gia","name":"Liêm đao (ma đao của lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"trangThai":"hong","blurb":"Thanh ma liêm đao do hắc giáp lão giả lấy ma khí và ma niệm ngưng hóa, ma hồn phân thể dung nhập mới thành ma đao thật.","detail":"Hắc giáp lão giả vuốt ngực khải giáp, ma khí đen ngưng thành một thanh liêm đao tỏa ma diễm, ẩn chứa quy tắc siêu thoát thiên địa làm không gian nứt vỡ, còn ở giữa hư-thực chuyển hóa. Ma hồn phân thể (ma ảnh một sừng từ mi tâm lão giả) hóa khói đen nhập vào liêm đao khiến đao sống lại thành ma đao thật, bắn về Vương Lâm. Khi va chạm kiếm khí của Lăng Thiên Hậu, ma đao tan vỡ cùng ma ảnh không cam lòng tiêu tan.","nguon":["@c0564"]},{"id":"tui-tru-vat-vuong-lam-de-lai","name":"Túi trữ vật Vương Lâm để lại","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Thiết Nham","Chu Như"],"trangThai":"dang-co","blurb":"Túi trữ vật Vương Lâm để lại năm xưa, Thiết Nham giữ mà không dám đụng.","detail":"Năm xưa Vương Lâm để lại túi trữ vật này; Thiết Nham bao năm vì cảm kích lẫn kính sợ nên không dám mở. Ông hứa sẽ lập tức trao cho Chu Như khi nàng đạt Nguyên Anh kỳ, xem như phần thưởng và di vật của ân công.","nguon":["@c0567"]},{"id":"pho-tuong-vuong-lam-van-thien-tong","name":"Pho tượng Vương Lâm","category":"khac","categoryLabel":"Tượng đài","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Pho tượng tạc Vương Lâm đặt ở Vân Thiên Tông, được người quen và Chu Tước Tử kính ngưỡng.","detail":"Pho tượng tạc hình Vương Lâm đặt tại Vân Thiên Tông — đất thánh mới của Chu Tước tinh. Mỗi lần gặp chuyện lớn Chu Vũ Thái (Chu Tước Tử) đều tới yên lặng nhìn pho tượng; Chu Như và Thiết Nham đều cúi chào, kính ngưỡng.","nguon":["@c0567"]},{"id":"de-kiem-yeu-de-co-van-phong","name":"Đế Kiếm (của Yêu Đế)","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"","soHuu":["Cổ Vân Phong"],"trangThai":"dang-co","blurb":"Bảo kiếm của Yêu Đế Cổ Vân Phong, cất trong hư vô, kiếm linh là cháu gái Song nhi.","detail":"Đế kiếm xé hư không xuất hiện theo lệnh Yêu Đế, chấn động rít bén nhọn, phóng kiếm khí phủ kín bốn phía công kích Vương Lâm và Hứa Lập Quốc. Năm xưa Vương Lâm còn Anh Biến hậu kỳ rất kiêng kị thanh kiếm này, nhưng nay đạt Vấn Đỉnh chỉ hừ lạnh đã chấn vỡ toàn bộ kiếm khí. Yêu Đế hư không nắm một cái thu kiếm về tay.","nguon":["@c0570"]},{"id":"ngoc-gian-trang-yeu-de","name":"Ngọc giản trắng (của Yêu Đế)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Quả ngọc giản màu trắng chứa yêu khí độc đáo khó bắt chước, coi như Yêu Đế đích thân tới.","detail":"Yêu Đế Cổ Vân Phong trao cho Vương Lâm quả ngọc giản trắng mang yêu khí độc đáo khó mô phỏng. Ai cầm ngọc giản coi như được Yêu Đế đích thân ủy thác, có quyền điều động Thiên soái giết kẻ bất kính; kèm tuyên bố Vương Lâm là sứ giả Tổ Linh để tiện hành sự.","nguon":["@c0570"]},{"id":"yeu-tinh-dan-dien-yeu-de","name":"Yêu tinh trong đan điền Yêu Đế","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Cổ Vân Phong"],"trangThai":"dang-co","blurb":"Viên yêu tinh lớn khoảng nắm tay nằm trong đan điền Cổ Vân Phong, không tỏa yêu lực nhưng khiến Vương Lâm đặc biệt chú ý.","detail":"Dưới tu vi Vấn Đỉnh, Vương Lâm nhìn ra trong đan điền Yêu Đế có một viên yêu tinh lớn khoảng nắm tay. Tuy không tỏa yêu lực, viên yêu tinh này càng khiến hắn chú ý, gợi mở bí mật của Cổ Vân Phong.","nguon":["@c0570"]},{"id":"xa-than-xa-573","name":"Xạ Thần Xa","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên giới","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khí giới cực mạnh do tiên nhân chế tạo, có năm đạo phong ấn mỗi đạo phong một hồn thú.","detail":"Vật tiên giới, khí giới cực mạnh do tiên nhân chế tạo, được ban thưởng tên Xạ Thần. Có năm đạo phong ấn, mỗi đạo phong một hồn thú: đạo thứ nhất mở ra có thể uy hiếp tu sĩ Anh Biến hậu kỳ đại viên mãn; đạo thứ hai phong hồn thú Lôi với lôi quang truy đuổi, uy lực rất mạnh. Muốn thật sự nhận chủ phải in đủ bảy đạo huyết phù, trong đó hai đạo phải sau khi giải phong ấn thứ tư mới in được. Trước nay Vương Lâm phải nhờ Khu Thú Quyển mới dùng được khi tu vi chưa đủ.","nguon":["@c0573"]},{"id":"khu-thu-quyen-573","name":"Khu Thú Quyển","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vòng đồng cổ xưa giúp Vương Lâm khống chế hồn thú trong Xạ Thần Xa khi tu vi chưa đủ.","detail":"Vòng đồng cổ xưa khắc vô số phù văn và thượng cổ hung thú, còn vài vết rách nhỏ do hồn thú cắn trả. Vật từ nơi Cổ Thần do tu sĩ dưới trướng Thác Sâm tặng để Vương Lâm hiệp trợ; mấy trăm năm qua giúp hắn dùng được Xạ Thần Xa dù tu vi chưa đủ. Khi mở đạo phong ấn thứ hai thì chắc chắn sụp đổ vì sự mạnh mẽ của hồn thú, nên Vương Lâm chọn hàng phục hồn thú để bảo tồn nó.","nguon":["@c0573"]},{"id":"huyet-phu-xa-than-xa","name":"Huyết phù (bảy đạo Xạ Thần Xa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Phù do tiên nhân chế tạo Xạ Thần Xa lưu lại; in đủ bảy đạo thì xe nhận chủ.","detail":"Phù do tiên nhân chế tạo Xạ Thần Xa lưu lại, tổng cộng bảy đạo, in đủ thì Xạ Thần Xa thật sự nhận chủ; trong đó hai đạo phải sau khi giải phong ấn thứ tư mới in được. Vương Lâm cắn đầu ngón tay trái vẽ huyết phù đỏ in vào mi tâm hồn thú để hàng phục.","nguon":["@c0573"]},{"id":"hon-thu-loi-xa-than-xa","name":"Hồn thú Lôi (Xạ Thần Xa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hồn thú bị phong trong đạo phong ấn thứ hai của Xạ Thần Xa, mang lực lượng Lôi.","detail":"Hồn thú bị phong trong Xạ Thần Xa; thân trăm trượng như tòa núi nhỏ, mắt đỏ bừng, ý chí bất khuất. Dưới đạo phong ấn thứ hai mang lực lượng Lôi. Vương Lâm đè nó xuống, vẽ huyết phù vào mi tâm, mở đạo phong ấn thứ nhất, đánh vỡ miệng nó; thân nó hóa thành vô số ánh sáng đen chui vào da Vương Lâm tới Nguyên thần.","nguon":["@c0573"]},{"id":"hon-thu-loi-thu-xa-than-xa","name":"Hồn thú → Lôi Thú (Xạ Thần Xa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","aliases":["Lôi Thú"],"blurb":"Hồn thú trong Xạ Thần Xa thứ hai, sau khi mở đạo phong ấn thứ hai tiến hóa thành Lôi Thú mọc sừng bạc, uy lực đủ đối kháng Vấn Đỉnh trung kỳ.","detail":"Hồn thú trong Xạ Thần Xa thứ hai, ban đầu thân trăm trượng như t��a núi nhỏ. Khi Vương Lâm in các đạo huyết phù để kích tiến hóa, thân co rút dần còn mười trượng, ánh hồng trong mắt tuôn ra gần bảy thước. Sau khi mở đạo phong ấn thứ hai, lôi điện đánh xuống bao quanh, nó hóa thành Lôi Thú — loài hiếm hơn cả kỳ lân ở tiên giới — mọc một cây sừng bạc. Theo ngọc giản, mở hoàn mỹ phải ra sừng vàng; chỉ ra sừng bạc nhưng khi hạ lạc ấn lại thoáng hiện tia sáng vàng. Uy lực Lôi Thú đủ đối kháng Vấn Đỉnh trung kỳ.","nguon":["@c0574"]},{"id":"huyet-phu-vuong-lam-xa-than-xa","name":"Huyết phù (luyện Xạ Thần Xa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Các đạo phù do Vương Lâm tạo bằng cách dung hợp khí Nguyên thần, in lên hồn thú để kích tiến hóa và hạ lạc ấn.","detail":"Bảy đạo huyết phù dung hợp khí Nguyên thần, mỗi đạo in vào kích thích hồn thú tiến hóa thêm một bậc. Vương Lâm in liên tiếp lên trán hồn thú; tới đạo thứ tư thì xuyên qua tia chớp đặt lên mi tâm Lôi Thú — vị trí ấn ký duy nhất do người chế tạo cố ý để lại để hạ lạc ấn, hoàn tất khống chế.","nguon":["@c0574"]},{"id":"tien-chung-cam-che","name":"Tiên chủng","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Lão Tổ Liên minh","Tôn Vân Sơn"],"trangThai":"dang-co","blurb":"Cấm chế tiên gia biểu hiện thành vân xanh dày đặc toàn thân, do Lão Tổ mang đến trước khi tiên giới sụp đổ.","detail":"Cấm chế tiên gia của Lão Tổ Liên minh, biểu hiện thành vô số đường vân xanh dày đặc lan từ mi tâm ra toàn thân người bị khống chế (Tôn Vân Sơn). Phát ra tiên khí mỏng manh, đích xác là vật ở Tiên giới; được nói trừ Lão Tổ ra không ai phá được. Vương Lâm xác nhận bản chất qua quan sát và lời Tôn Vân Sơn.","nguon":["@c0576"]},{"id":"toai-ngoc-tien-ve","name":"Toái ngọc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh ngọc tiên giới nhỏ như móng tay trong Nguyên thần Tiên vệ, ẩn chứa tiên lực khổng lồ kèm một đạo ý niệm.","detail":"Mảnh ngọc tiên giới còn lại sau khi Vương Lâm luyện hóa Nguyên thần Tiên vệ, nhỏ như móng tay. Ẩn chứa tiên lực khổng lồ nhưng không thể hấp thu trực tiếp vì có một đạo ý niệm. Nguyên thần tu sĩ dung hợp Toái ngọc (cùng ý niệm tương dung) có thể đạt tu vi tương đương Vấn Đỉnh sơ kỳ, xác suất cực thấp. Đây cũng là nguồn tu vi Vấn Đỉnh giả mà Lão Tổ ban cho Tiên vệ. Vương Lâm thu vào túi trữ vật.","nguon":["@c0576","@c0577"]},{"id":"ngoc-gian-vuong-lam-ton-van-son","name":"Ngọc giản (Vương Lâm đưa Tôn Vân Sơn)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Tôn Vân Sơn"],"trangThai":"dang-co","blurb":"Vật phòng thân chứa cấm chế trì hoãn Tiên chủng lúc nguy hiểm.","detail":"Ngọc giản Vương Lâm đưa cho Tôn Vân Sơn khi rời đi: chứa cấm chế tuy không hóa giải hoàn toàn Tiên chủng nhưng lúc nguy hiểm có thể trì hoãn.","nguon":["@c0576"]},{"id":"tien-thu-chi-luong","name":"Tiên thú chi lương","aliases":["Tiên lương","Tiên chủng"],"category":"khac","categoryLabel":"Vật phẩm tiên giới","phamCap":"Tiên giới","soHuu":["Lão già thấp bé (Toà thành trắng)"],"trangThai":"mat","blurb":"Khối ngọc thạch xanh hoá vô số sợi tơ dài tấn công nuốt đối thủ; thiên địch của Tiên Kỳ Lân.","detail":"Khối ngọc thạch màu xanh to bằng nắm tay, hô “Tiên chủng!” thì hoá vô số sợi tơ dài màu xanh phát âm thanh bén như dây đàn, lao tới tấn công nuốt địch. Lão già không khống chế hoàn toàn được. Đây chính là thứ Vương Lâm từng gặp thành đại quân khổng lồ tại động phủ năm xưa và thấy trên người Tôn Vân Sơn. Là thiên địch của Tiên Kỳ Lân — bị đầu Kỳ Lân thú trong Hồn Phiên hút sạch chuyển thành khí bổ dưỡng.","nguon":["@c0578"]},{"id":"toa-than-but","name":"Toả Thần bút","cn":"","aliases":["Tiên bút"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên giới","soHuu":["Lão tổ (lão già dáng cực kỳ thấp bé)"],"trangThai":"mat","blurb":"Bút lông Tiên giới thân trong suốt, đầu lông trắng; vật tuỳ thân của lão già khi còn ở Tiên giới, dùng điểm hoá tu sĩ hạ giới.","detail":"Cây bút lông vừa xuất hiện đã tản uy nghiêm khiến cả Kỳ Lân thú lộ kinh hãi. Lão già phun tiên huyết lên đầu bút vẽ ra phù văn truyền lực lượng mênh mông, giống đúc phù văn trên Tôn Long chi lộ ngoài Tiên phủ mà Vương Lâm từng gặp; nhưng lão chỉ biết một bút nên không phát ra uy lực chân chính, bị Thiên lôi đánh sụp. Đây là một trong bốn bút liên quan phù văn Tôn Long chi lộ Vương Lâm từng dung hợp, vì thế hắn quyết đoạt. Lão khống chế kém nên cùng đường ném bút vào hư vô để tẩu thoát; Vương Lâm sai Hứa Lập Quốc dẫn Tiểu hắc tử đuổi theo.","nguon":["@c0579"]},{"id":"khon-tien-vong","name":"Khốn Tiên võng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên giới","soHuu":["Lão tổ (lão già dáng cực kỳ thấp bé)"],"trangThai":"dang-co","blurb":"Tấm lưới màu xanh Tiên giới mà lão già rút ra khi cùng đường; lão khống chế còn kém hơn cả Toả Thần bút.","detail":"Khi bị Vương Lâm dồn tới cùng đường, lão già cắn răng xuất ra tấm lưới màu xanh. Lão thừa nhận khống chế Khốn Tiên võng còn kém hơn Toả Thần bút, chưa từng dùng nó đối địch, van cầu tấm lưới nhận rõ kẻ thù và đừng trói mình, kể năm xưa từng giải thoát nó coi như có duyên phận. Lão không muốn dùng trừ khi vạn bất đắc dĩ vì thấy cái lưới quá mức quỷ dị — gợi mở một pháp bảo Tiên giới có ý thức, nguy hiểm.","nguon":["@c0579"]},{"id":"ky-lan-thu-lao-gia","name":"Kỳ Lân thú (lão già)","cn":"","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Lão tổ (lão già dáng cực kỳ thấp bé)"],"trangThai":"dang-co","blurb":"Tiên thú của lão già thấp bé, đầu cực lớn, ăn các đoàn màu xanh Tiên lương trên mi tâm tu sĩ.","detail":"Kỳ Lân thú liếm mép lắc cái đầu cực lớn, chăm chú nhìn đoàn màu xanh Tiên lương trên mi tâm các tu sĩ vì ăn vẫn chưa no. Khi lão già rút Toả Thần b��t, nó lộ kinh hãi. Trong lúc loạn chiến, nó gầm thét chấn các đoàn màu xanh trên mi tâm tu sĩ thành sợi tơ xanh nuốt vào miệng. Nuôi và điều khiển bằng Tiên lương.","nguon":["@c0579"]},{"id":"tu-thu-ta-hon","name":"Tử Thử Tà hồn","cn":"","category":"phap-bao","categoryLabel":"Hồn thú","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một trong ba hồn thú của Vương Lâm; sau khi cùng kiếm quang giết nữ tử thì ngậm giữ hồn phách của nàng.","detail":"Tử Thử Tà hồn là một trong ba hồn thú Vương Lâm điều khiển cùng Tam Tài kiếm trận. Khi ba kiếm quang xuyên thân nữ tử, Tử Thử Tà hồn ngậm giữ hồn phách của nàng.","nguon":["@c0584"]},{"id":"thuy-tinh-cua-boi-la","name":"Thủy tinh của Bối La","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo tra xét do Bối La đưa cho Vương Lâm, dùng dò địa hình hung hiểm của Triều Tịch thâm uyên.","detail":"Vật Bối La đưa cho Vương Lâm dùng để tra xét địa hình hung hiểm của Triều Tịch thâm uyên trước khi tiến vào. Qua tra xét, Vương Lâm biết có vài nơi với tu vi của hắn vẫn phải mạo hiểm.","nguon":["@c0589"]},{"id":"o-ue-chi-nhuc-do-kien","name":"Ô uế chi nhục","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Đỗ Kiến"],"trangThai":"mat","blurb":"Bướu thịt đen do Đỗ Kiến luyện hóa nhiều năm, tự nổ tỏa mùi thối khiến tu sĩ dính phải lở loét toàn thân.","detail":"Một bướu thịt màu đen, hao tổn tâm cơ nhiều năm Đỗ Kiến mới luyện thành. Khi ném ra nó tự nổ tung, tỏa mùi thối nồng nặc; tu sĩ chạm phải sẽ lở loét toàn thân. Trong trận với Vương Lâm, nó bị Hoàng Tuyền quét tới cuốn vào trong và nuốt mất.","nguon":["@c0591"]},{"id":"tien-but-vuong-lam","name":"Tiên bút","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên khí","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bút lông pháp bảo sáng lấp lánh, phối hợp phù chú tiên gia để vẽ ký hiệu thần thông.","detail":"Tiên bút là bút lông pháp bảo phát sáng, Vương Lâm dùng để vẽ ký hiệu bảy nét tiên gia — mỗi nét dung nhập một tia nguyên thần, hợp thành hình tròn ẩn chứa càn khôn. Lần trước hắn chỉ vẽ một nét đã thu hút phi trùng; lần này vẽ tới bảy nét, cực hạn hiện thời.","nguon":["@c0594"]},{"id":"vu-tien-kiem","name":"Vũ tiên kiếm","cn":"","aliases":["Vũ chi tiên kiếm"],"category":"than-khi","categoryLabel":"Tiên khí","phamCap":"Bảo vật s�� một tiên giới","soHuu":["Chu Dật","Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Tiên kiếm được xưng là bảo vật số một tiên giới, chứa kiếm linh Chu Dật và bản mệnh kiếm khí.","detail":"Vũ chi tiên kiếm là tiên kiếm được xem là bảo vật số một tiên giới. Bên trong là kiếm linh — chính là Chu Dật, được thi thể nữ tử áo trắng dùng tiên lực nâng lên — cùng bản mệnh kiếm khí 99 đạo. Lăng Thiên Hậu tóm được một thanh Vũ tiên kiếm nhưng không dám xuất ra trước Chu Dật vì sẽ bị đối phương điều khiển.","nguon":["@c0594"]},{"id":"bon-bao-kiem-nguyen-than-luyen-tien-hoa-ma","name":"Bốn thanh bảo kiếm Nguyên Thần","category":"than-khi","categoryLabel":"Kiếm pháp bảo","phamCap":"Tiểu Thiên Địa luyện thành","soHuu":["Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Bốn thanh kiếm là bốn tiểu Thiên Địa Lăng Thiên Hậu luyện thành, cắm bốn phía Luyện Tiên Hóa Ma đại trận.","detail":"Bốn tiểu Thiên Địa được Lăng Thiên Hậu luyện thành bốn thanh kiếm Nguyên Thần, cắm bốn phía trong Luyện Tiên Hóa Ma đại trận để phong ấn Chu Dật. Ba trong bốn thanh có gắn quả cầu thần niệm bay quanh; quả cầu thứ tư bị Chu Dật phóng bản mệnh kiếm khí đâm vỡ.","nguon":["@c0594"]},{"id":"ngoc-gian-thanh-lam","name":"Ngọc giản của Thanh Lâm","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Ngọc giản thông tin","soHuu":["Vương Lâm","Chu Dật"],"trangThai":"dang-co","blurb":"Ngọc giản chứa thông tin về Thanh Sương và tiên đế Thanh Lâm.","detail":"Vương Lâm ném ngọc giản này cho Chu Dật. Sau khi dụng thần thức xem xét, Chu Dật mới biết Đình nhi chính là Thanh Sương — nhi nữ tiên đế Thanh Lâm, và nơi Thanh Lâm có thể đang ẩn náu chữa thương ở mảnh đất Yêu Linh.","nguon":["@c0595"]},{"id":"vu-tien-kiem-bo-bon-thanh","name":"Vũ tiên kiếm (bộ bốn thanh)","cn":"","category":"than-khi","categoryLabel":"Tiên kiếm","phamCap":"Tiên khí","soHuu":["Chu Dật","Vương Lâm"],"trangThai":"dang-co","blurb":"Bộ kiếm tiên bốn thanh thuộc về kiếm linh nữ thi áo trắng; Chu Dật tách một thanh trao vĩnh viễn cho Vương Lâm.","detail":"Bộ kiếm tiên vốn có bốn thanh, đời đời kiếp kiếp thuộc về kiếm linh — nữ thi mặc bạch y. Dù bị người khác đoạt, chỉ cần còn Chu Dật thì các kiếm chỉ tạm thời bị điều khiển, gặp Chu Dật li��n trở về. Chu Dật phá lạc ấn tách một thanh trao vĩnh viễn cho Vương Lâm, còn ba thanh do Chu Dật điều khiển; thanh trao Vương Lâm kiếm linh khác không điều khiển được.","nguon":["@c0596"]},{"id":"nguyen-than-kiem-lang-thien-hau","name":"Nguyên Thần kiếm (của Lăng Thiên Hậu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo (kiếm)","phamCap":"Cao cấp","soHuu":["Lăng Thiên Hậu"],"trangThai":"dang-co","blurb":"Bảo kiếm do Lăng Thiên Hậu luyện hóa từ bốn tiểu thiên địa, bên trong ẩn chứa đạo kiếm khí bản mệnh.","detail":"Lăng Thiên Hậu luyện hóa bốn tiểu thiên địa thành Nguyên Thần kiếm; bên trong ẩn chứa các đạo kiếm khí bản mệnh mà đệ tử Đại La kiếm tông sử dụng. Điểm vào mi tâm sẽ bật ra một đạo kiếm khí uy lực lớn, đủ phá Tử khí.","nguon":["@c0601"]},{"id":"bay-ngan-cham-that-ma-cham","name":"Bảy ngân châm (Thất Ma Châm)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Bộ bảy cây châm pháp bảo khống chế của Tham Lang.","detail":"Bảy cây châm cắm trên đầu Văn thú lớn, hóa thành bảy đạo ngân quang. Tham Lang dùng chúng để ép khống chế Văn thú, và khi thu về có thể kết thành một màn bảo vệ màu bạc che thân khi lao vào hợp chiến.","nguon":["@c0602"]},{"id":"bao-kiem-than-long","name":"Bảo kiếm của Thần Long","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thần Long"],"trangThai":"dang-co","blurb":"Đại kiếm pháp bảo của Thần Long, hóa hắc long tấn công.","detail":"Đại kiếm hóa thành hắc long mang kiếm khí lao vào địch; khi bị Phệ Tử Nhất Thức phá thì lắc lư bay về tay Thần Long. Qua thần thông Toái Kiếm Hóa Thần, kiếm nứt vỡ lột một lớp da rồi mảnh vụn mang huyết khí tái sinh hắc long lần hai mạnh hơn.","nguon":["@c0602"]},{"id":"ngon-nui-tien-gioi-son-hon","name":"Ngọn núi tiên giới (chứa sơn hồn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"hong","blurb":"Ngọn núi tiên giới Tham Lang đoạt và phong ấn, ẩn chứa sơn hồn cùng tiên lực có sẵn.","detail":"Núi nhỏ cất trong túi trữ vật, khi tung ra lớn bổng thành ngọn núi hơn trăm trượng khắc vô số phù văn lóe sáng quỷ dị. Tham Lang đoạt nó từ tiên giới rồi phong ấn mấy vạn năm trước; bản thân ngọn núi ẩn chứa tiên lực có sẵn (không phải của Tham Lang). Khi bị Phệ Tử nhị thức rút sơn hồn thì nứt vỡ thành đá vụn rơi xuống.","nguon":["@c0602"]},{"id":"lenh-bai-trong-suong-mu","name":"Lệnh bài trong sương mù","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":[],"trangThai":"","blurb":"Lệnh bài dần hiện ra trong quả cầu sương mù co lại.","detail":"Khi quả cầu sương mù phía xa co lại từ trăm trượng còn bảy thước, một lệnh bài do chính sương mù ngưng tạo dần hiện ra cùng một người sống bên trong là đệ tử Đại La kiếm tông. Tham Lang lộ vẻ tham lam, cất bước tiến tới muốn đoạt lấy.","nguon":["@c0602","@c0606"]},{"id":"dai-dinh-can-khon-nghich-chuyen","name":"Đại đỉnh Càn Khôn nghịch chuyển","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Cái đỉnh đen kịt cao cỡ đầu người của Tham Lang, niệm chú đảo ngược trời đất và vị trí đối tượng.","detail":"Đại đỉnh cao cỡ đầu người, toàn thân đen kịt, khắc vô số phù văn và hình thú, tỏa khí tức hồng hoang. Khi Tham Lang rống ‘Càn Khôn nghịch chuyển, thiên địa phiên thân’, đỉnh chấn động phóng hắc quang chiếu khắp thiên địa, đảo ngược trời đất và đảo vị trí các đối tượng — khiến Vương Lâm đang ở phía trước gần cửa ra lại rơi vào vị trí Thần Long bị sương mù vây khốn.","nguon":["@c0603"]},{"id":"thien-me-huong","name":"Thiên Mê Hương","category":"khac","categoryLabel":"Chí bảo tiên giới","phamCap":"Chí bảo tiên giới","soHuu":["Tham Lang"],"trangThai":"da-dung","blurb":"Đoạn đàn hương dài cỡ ngón tay, tỏa khói xanh tạo tầng sương mê bao trùm đối thủ.","detail":"Thoạt nhìn như một đoạn đàn hương phàm tục dài cỡ ngón tay, nhưng là chí bảo tiên giới. Khi đốt, tỏa khói xanh mờ mịt hình thành tầng sương mê bao trùm; Tham Lang đau lòng mới chịu xuất ra để dùng khói mê trùm cả đàn Văn thú mà thoát vòng vây, đồng thời nương sương đuổi theo và vây khốn đối thủ.","nguon":["@c0603"]},{"id":"cai-dinh-co-than-do-ti-tham-lang","name":"Cái đỉnh (của cổ thần Đồ Ti)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Pháp bảo do cổ thần Đồ Ti luyện, có thể nghịch chuyển Càn Khôn, đổi chỗ người, mang theo cỗ thần uy không thể chống cự.","detail":"Cái đỉnh trong tay Tham Lang vốn do cổ thần Đồ Ti luyện chế. Nó có thể nghịch chuyển Càn Khôn, đổi chỗ giữa hai người (đã đổi chỗ Vương Lâm với Thần Long), mang theo cỗ thần uy kinh khủng khiến Thần Long khiếp sợ phải bỏ chạy. Vương Lâm nhận ra cái đỉnh, cay đắng vì bảo vật cổ thần Đồ Ti cũng rơi vào tay Tham Lang.","nguon":["@c0604"]},{"id":"de-nhi-nguyen-than-thai-co-loi-long-tham-lang","name":"Đệ nhị nguyên thần Tham Lang / Thái Cổ Lôi Long","cn":"","category":"phap-bao","categoryLabel":"Linh thể – pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"hong","blurb":"Linh thân Thái Cổ Lôi Long bị Tham Lang phong ấn luyện thành đệ nhị nguyên thần lôi hệ; bị Vương Lâm diệt thì Lôi Long thoát ấn hóa thanh long.","detail":"Thời Trúc Cơ kỳ Tham Lang rớt vách núi, tình cờ tìm thấy ấu thể linh thân Thái Cổ Lôi Long đang hôn mê trong địa huyệt. Sau hắn mua được Thái Cổ ma khí (pháp bảo vứt đi) hóa thành lạc ấn phong ấn Lôi Long, tới Vấn Đỉnh kỳ luyện thành đệ nhị nguyên thần lôi hệ — thân trong suốt như người tí hon thủy tinh, quanh thân lôi cầu màu đen. Tham Lang không dám kích thích nó sợ Lôi Long tỉnh dậy thoát khống chế. Khi Vương Lâm phá nát lạc ấn mi tâm và thân thể đệ nhị nguyên thần, Thái Cổ Lôi Long thoát phong ấn, hóa thanh long toàn thân lôi quang uy danh hiển hách, ôm cừu hận đuổi theo.","nguon":["@c0604"]},{"id":"binh-phong-son-ha-do-tham-lang","name":"Bình phong (dáng dấp Sơn Hà đồ)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Tấm bình phong vẽ sơn thủy đạm mặc, Tham Lang ném ra hóa lớn hơn mười trượng, có dáng dấp Sơn Hà đồ tiên giới, phát lực hút lớn.","detail":"Một trong vô số pháp bảo Tham Lang lĩnh ngộ trong hơn vạn năm kẹt ở Chu Tước tinh. Hắn ném ra tấm bình phong vẽ sơn thủy đạm mặc, hóa lớn hơn mười trượng, có dáng dấp Sơn Hà đồ tiên giới, phát ra lực hút lớn hòng thu người. Chu Dật phải phóng hai đạo bổn mạng kiếm khí còn lại để đối kháng.","nguon":["@c0604"]},{"id":"loi-thu-xa-than-xa-c0604","name":"Lôi Thú","cn":"","category":"phap-bao","categoryLabel":"Tiên thú lôi hệ","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tiên thú lôi hệ hiện thân từ Xạ Thần Xa, phun thanh khí, nuốt lôi cầu, thần lôi và điện long, đuổi theo bảo vệ Vương Lâm.","detail":"Vương Lâm thả Xạ Thần Xa召 ra Lôi Thú — tiên thú lôi hệ. Lôi Thú nuốt hai lôi cầu cửu tinh liên châu, rồi nuốt cả thần lôi lẫn điện long của đệ nhị nguyên thần Tham Lang, đuổi theo bảo vệ Vương Lâm trong cuộc đấu lôi pháp dưới vực sâu.","nguon":["@c0604"]},{"id":"loi-chuy-bua-dien-quang-tham-lang","name":"Lôi chùy (búa điện quang)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tham Lang"],"trangThai":"hong","blurb":"Vũ khí của đệ nhị nguyên thần Tham Lang, bay ra từ mi tâm; đánh ra điện long, ngưng màu máu để phát Diệt Tiên Lôi.","detail":"Cây búa điện quang bay ra từ mi tâm đệ nhị nguyên thần Tham Lang, đánh ra điện long công kích. Khi ngưng tụ chuyển màu máu, lôi chùy phát ra Diệt Tiên Lôi đánh vào vách đá tạo điện võng đỏ vây khốn Vương Lâm. Hỏng theo đệ nhị nguyên thần khi bị Vương Lâm diệt.","nguon":["@c0604"]},{"id":"thai-co-ma-khi-tham-lang","name":"Thái Cổ ma khí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo gốc","phamCap":"","soHuu":["Tham Lang"],"trangThai":"dang-co","blurb":"Pháp bảo Tham Lang mua được như đồ vứt đi, nghiên cứu ra là Thái Cổ ma khí, hóa thành lạc ấn phong ấn Thái Cổ Lôi Long.","detail":"Tham Lang mua được một pháp bảo tưởng như vứt đi, nghiên cứu mới biết là Thái Cổ ma khí. Hắn dùng nó hóa thành lạc ấn phong ấn linh thân Thái Cổ Lôi Long, làm nền tảng luyện thành đệ nhị nguyên thần lôi hệ.","nguon":["@c0604"]},{"id":"thai-co-loi-long","name":"Thái Cổ Lôi Long","cn":"","aliases":["Thanh Long"],"category":"khac","categoryLabel":"Sinh vật Thái Cổ","phamCap":"Thái Cổ Chi Thú","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Sinh vật cấp Thái Cổ Chi Thú, tương truyền sinh từ sấm sét, con cưng của Thiên Đạo; bị Vương Lâm nuốt vào nguyên thần.","detail":"Thái Cổ Lôi Long còn gọi Thanh Long, cấp Thái Cổ Chi Thú, tương truyền sinh ra từ sấm sét tích tụ, từng có thời thay Thiên Đạo nắm sức mạnh sấm sét — nuốt nó không khác gì nuốt thiên lôi, đến đám Thiên Vận Tử cũng không dám. Bị Vương Lâm nuốt vào nguyên thần, mới luyện hóa được một phần năm, phần còn lại bị phong ấn, khiến nguyên thần Vương Lâm biến dị hoàn toàn thành dạng Thiên Lôi.","nguon":["@c0606"]},{"id":"ngoc-gian-bi-thuat-tien-ve","name":"Ngọc giản bí thuật Tiên Vệ","category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản ghi các bước chế tạo Tiên Vệ cực phức tạp, chứa thần thông chỉ Tiên Vệ mới thi triển được.","detail":"Ghi lại trọn vẹn bốn bước luyện chế Tiên Vệ, từng bước không thể sai sót. Trong ngọc giản còn chứa một loại thần thông mà chỉ Tiên Vệ mới thi triển được — đây chính là lý do cốt lõi khiến Vương Lâm liều luyện chế Tiên Vệ, mong có cơ hội rời khỏi nơi này.","nguon":["@c0608"]},{"id":"doa-hoa-hong-mau-lam","name":"Đóa hoa hồng màu lam","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đóa hoa hồng màu lam trong túi trữ vật Vương Lâm; nhìn vào hiện ra thân ảnh đỏ như lửa.","detail":"Khi dọn dẹp túi trữ vật để lấy vật liệu luyện chế, đóa hoa hồng màu lam bỗng xuất hiện trong tay Vương Lâm. Nhìn đóa hoa, trước mắt hắn hiện ra một thân ảnh đỏ như lửa khiến hắn do dự, cuối cùng thu hồi đóa hoa và không đưa vào luyện hóa — gắn với ký ức hoặc người liên quan, còn để ngỏ.","nguon":["@c0608"]},{"id":"khoi-loi-tien-ve-thu-nhat","name":"Khôi lỗi Tiên Vệ (thứ nhất)","category":"phap-bao","categoryLabel":"Pháp bảo (khôi lỗi)","phamCap":"Âm dương hư thực","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khôi lỗi Tiên Vệ đầu tiên Vương Lâm luyện chế thành công, khí tức ngang cảnh giới âm dương hư thực.","detail":"Thân khôi lỗi gầy gò ánh vàng mờ, luyện từ Thiên Quỷ làm hư thể và nguyên thần Đỗ Kiến làm nền, dung hợp qua hơn nửa năm. Sau khi nhỏ giọt máu kích hoạt, nó mở hai mắt trống rỗng mà linh hoạt sắc bén, khí tức tương đương cảnh giới âm dương hư thực (xấp xỉ Tư Đồ Nam năm đó, hơi kém một chút). Vương Lâm đổ trăm vạn đạo sát lục chi khí khiến mắt nó tràn sát lục chi ý rồi ẩn giấu, gắn ngọc giản truyền vài thần thông riêng của Tiên Vệ; nó chịu khống chế tự nhiên và theo lệnh ‘Ẩn’ nấp vào thân ảnh chủ nhân.","nguon":["@c0609"]},{"id":"tan-ma-chi-hon","name":"Tán Ma Chi Hồn","category":"khac","categoryLabel":"Hồn / Năng lực","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hồn vật Vương Lâm sở hữu, dấu ấn của hắn ngày càng sâu, định tế dưỡng thành nguyên thần thứ hai.","detail":"Một hồn vật mạnh mẽ trong tay Vương Lâm; dấu ấn khống chế của hắn cài lên nó ngày càng sâu, hắn dự định nuôi dưỡng nó thành nguyên thần thứ hai. Trong chương này hắn cân nhắc dùng Tán Ma Chi Hồn để luyện khôi lỗi Tiên Vệ nhưng thấy việc khống chế nó quá phiền phức nên cuối cùng chọn Thiên Quỷ thay thế.","nguon":["@c0609"]},{"id":"roi-khac-che-thien-quy","name":"Roi khắc chế Thiên Quỷ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cây roi Vương Lâm dùng để khắc chế Thiên Quỷ.","detail":"Một cây roi đúng là vật khắc chế Thiên Quỷ. Khi Thiên Quỷ gào thét chống cự lúc bị nhấn vào lông mày khôi lỗi để luyện hóa, Vương Lâm quất roi khiến nó kêu thảm và buộc phải khuất phục.","nguon":["@c0609"]},{"id":"tieu-cau-bach-quang-uyen-nhi","name":"Tiểu cầu bạch quang (Uyển Nhi)","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tiểu cầu phát bạch quang mỏng manh, bên trong có bóng hình mờ ảo của Uyển Nhi.","detail":"Một tiểu cầu phát ra bạch quang yếu ớt trôi bên cạnh Vương Lâm trong khe tối. Bên trong có bóng hình mờ ảo xinh đẹp của Uyển Nhi làm bạn cùng hắn, tỏa hơi ấm bù đắp nỗi cô độc suốt những năm tháng tu đạo của hắn.","nguon":["@c0609"]},{"id":"lenh-bai-vao-dong-phu","name":"Lệnh bài vào động phủ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tín vật để tiến vào động phủ thực sự; Tham Lang vây Thần Long trong tử vụ vì lệnh bài này, hiện do Vương Lâm giữ.","detail":"Lệnh bài là tín vật để tiến vào động phủ thực sự. Tham Lang từng vây Thần Long trong tử vụ vì lệnh bài này nhưng thề không đoạt được; người thực sự cướp giữ lệnh bài là Vương Lâm của Thiên Vận Tông. Thần Long làm chứng từng thấy Vương Lâm giữ lệnh bài.","nguon":["@c0614"]},{"id":"xich-dieu-thach","name":"Xích diệu thạch","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Khoáng thạch","phamCap":"Chưa rõ","soHuu":["Tôn Tuyết Sơn","Nhiễm Nguyệt"],"trangThai":"dang-co","blurb":"Khối khoáng thạch nhóm bốn người Nhiễm Vân Tinh chiếm được khi thí luyện, nguyên cớ khiến Minh vụ trùng truy kích.","detail":"Vật bốn người Nhiễm Vân Tinh vô tình chiếm được trong khi thí luyện; chính vì giành lấy nó mà bị vô số Minh vụ trùng đuổi truy kích mấy ngày liền rồi bao vây. Tôn Tuyết Sơn hứa dùng Xích diệu thạch để báo đáp Vương Lâm, nhưng Vương Lâm không biết đó là vật gì nên không bị hấp dẫn.","nguon":["@c0615"]},{"id":"vong-ngoc-loi-dien-nhiem-nguyet","name":"Vòng ngọc toả lôi điện","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Nhiễm Nguyệt"],"trangThai":"dang-co","blurb":"Vòng tay nhỏ của Nhiễm Nguyệt toả lôi điện yếu ớt phát sáng, che phủ cả bốn người chống sương độc Minh vụ trùng.","detail":"Chiếc vòng ngọc nhỏ của Nhiễm Nguyệt toả lôi điện yếu ớt phát sáng, tạo lớp che phủ bốn người trong vòng vây sương độc; nếu không có nó cả nhóm đã bị Minh vụ trùng thôn tính tiêu tan nguyên thần. Vòng tay hấp thu phần lớn tiên lực của nàng, khiến tiên lực hao nhanh nhất trong nhóm.","nguon":["@c0615"]},{"id":"cuon-tranh-nu-tu-vuong-lam","name":"Cuộn tranh nữ tử","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thần bí","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bức tranh thần bí trong túi trữ vật Vương Lâm, tự bay ra hiện thân ảnh nữ tử không thấy mặt gọi ‘Đi xuống’.","detail":"Cuộn tranh tự bay ra khỏi túi trữ vật, hiện thân ảnh một nữ tử không nhìn thấy mặt, phát thanh âm mờ ảo gọi ‘Đi xuống’. Trước khi tranh xuất hiện, một tiểu cầu phát ánh sáng dịu dàng đã dung nhập vào tay Vương Lâm. Trong ba năm nữ tử này đã hiện ra bốn lần, mỗi lần đều kêu gọi như vậy. Vương Lâm dùng hai ngón tay tạo kiếm chém một cái khiến tranh cuộn lại im tiếng rồi ném trở lại túi trữ vật. Thân phận và mục đích nữ tử chưa rõ, liên hệ với tiểu cầu sáng và Truyền Tống Trận dưới đáy hố sâu.","nguon":["@c0610"]},{"id":"tieu-cau-anh-sang-diu-dang","name":"Tiểu cầu phát ánh sáng dịu dàng","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Quả cầu nhỏ tỏa ánh sáng dịu dàng dung nhập vào tay Vương Lâm ngay trước khi cuộn tranh nữ tử hiện ra.","detail":"Một tiểu cầu phát ánh sáng dịu dàng xuất hiện trong lòng bàn tay Vương Lâm và dung nhập vào tay hắn ngay trước thời điểm cuộn tranh nữ tử thần bí bay ra gọi ‘Đi xuống’. Mối liên hệ giữa tiểu c���u, cuộn tranh và lời gọi ‘Đi xuống’ chưa được làm rõ.","nguon":["@c0610"]},{"id":"buc-tranh-nu-tu-la-thien","name":"Bức tranh nữ tử (La Thiên tinh vực)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"mat","blurb":"Bức tranh tỏa ánh sáng nhu hòa, miễn nhiễm lực hút, chứa hồn nữ tử La Thiên tinh vực biết nhiều bí mật.","detail":"Tranh chỉ lộ bóng lưng nữ tử nhưng toát vẻ hấp dẫn; tỏa ánh sáng nhu hòa và miễn nhiễm lực hút của dòng xoáy. Hồn nữ tử trong tranh thuộc Hướng gia ở Đông Lâm tinh, La Thiên tinh vực, biết lai lịch thật của Thiên Nghịch châu và cách cứu sống tàn hồn. Tranh truyền lực lượng kỳ dị vào hai mắt Vương Lâm cho hắn nhìn xuyên dòng xoáy thấy La Thiên tinh vực. Cuối cùng Vương Lâm nhận ra âm mưu, ném tranh cắm sâu vào vách đá trong một cái khe, đánh ra vô số cấm chế phong ấn suốt mấy tháng, dùng cả con rối Tiên Vệ phong ấn triệt để rồi vỗ sụp cái khe chôn sâu.","nguon":["@c0612"]},{"id":"la-yeu-thach","name":"La Yêu thạch","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"","blurb":"Khoáng thạch là điều kiện duy nhất để khởi động truyền tống trận cổ về La Thiên tinh vực.","detail":"Truyền tống trận cổ ẩn dưới tảng đá ở đáy khe chỉ có thể khởi động nếu có La Yêu thạch; ngay cả tiên ngọc cũng vô dụng. Là đầu mối vật phẩm cần tìm nếu muốn tới La Thiên tinh vực.","nguon":["@c0612"]},{"id":"thien-nghich-chau-huyen-gia","name":"Thiên Nghịch Châu","category":"khac","categoryLabel":"Bảo vật","soHuu":[],"trangThai":"khong-ro","blurb":"Bảo vật mà đại trưởng lão Huyễn gia tới Liên Minh Tinh Vực tìm kiếm nhưng không được.","detail":"Thiên Nghịch Châu là bảo vật mà lão già đại trưởng lão Huyễn gia đến Liên Minh Tinh Vực tìm kiếm. Vì thu Mi nhi làm đệ tử và yêu quý nàng, lão bỏ việc tìm châu mà quay về La Thiên Tinh Vực.","nguon":["@c0616"]},{"id":"nguy-tien-bao-vuong-lam","name":"Ngụy tiên bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không bằng hạ phẩm Tiên Bảo","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bộ ba pháp bảo Vương Lâm tự luyện chế: phi kiếm, gương đồng, trâm cài tóc; dùng được tiên lực và ẩn ý cảnh thần thông.","detail":"Vương Lâm xuất vật liệu luyện khí, dùng nguyên thần khí hóa thành ba khuôn đúc: một phi kiếm, một gương đồng, một trâm cài tóc, rồi bấm niệm thần chú dung nhập cấm chế (kèm tia điện quang trong nguyên thần). Gương đồng nhập Tuế Nguyệt Ý Cảnh, trâm cài tóc nhập Thiên Huyễn Vô Tình Đạo, phi kiếm hạ một đạo na di ấn quyết. Hắn đặt tên là Ngụy tiên bảo — chất lượng không bằng cả hạ phẩm Tiên Bảo chân chính, nhưng dùng được tiên lực và ẩn ý cảnh thần thông; tu sĩ Anh Biến dù không có tiên lực cũng có thể dùng linh lực để vận, uy lực tăng nhiều. Riêng gương đồng còn được áp thủ pháp ngụy kế thừa bằng phong ấn đặc thù.","nguon":["@c0617"]},{"id":"hat-chau-xanh-nhiem-van-tinh","name":"Hạt châu màu xanh","cn":"","category":"khac","categoryLabel":"Khí cụ","phamCap":"Pháp thuật nhỏ (La Thiên Tinh Vực)","soHuu":[],"trangThai":"dang-co","blurb":"Hạt châu màu xanh to bằng nắm tay nạm trên nóc phòng xá, ẩn ba trận pháp tạo ánh sáng và hương thơm từ khói nến.","detail":"Khói nến bị hạt châu hấp thu, hóa nhiệt rồi ngưng thành quang tỏa ánh sáng êm dịu làm nguồn sáng duy nhất khi tắt nến, kèm mùi hương nhẹ không độc giúp tu sĩ thổ nạp nhanh hơn và là vật liệu luyện đan. Vương Lâm hứng thú vì chưa từng thấy, dùng nó dẫn khói khi luyện gương đồng.","nguon":["@c0617"]},{"id":"phi-kiem-tu-luyen-vuong-lam-c0618","name":"Phi kiếm tự luyện của Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bề ngoài tựa pháp bảo hạ phẩm (ẩn chứa điều khác biệt)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Thanh phi kiếm Vương Lâm vừa luyện chế, bề ngoài xấu xí kiếm quang tối tăm nhưng ẩn chứa thần thông phi thường.","detail":"Thanh phi kiếm Vương Lâm tự luyện chế, bề ngoài xấu xí, kiếm quang tối tăm. Lô Phong ở Bảo Hợp Lâu chỉ liếc mắt đã chê không bằng pháp bảo hạ phẩm và từ chối thu mua, dù gã cảm thấy kiếm có thần thông mà không thích. Nhưng văn sĩ trẻ Thanh Trúc Các dùng thần thức xem kĩ thì lộ vẻ kinh khiếp — phi kiếm ẩn chứa điều phi thường.","nguon":["@c0618"]},{"id":"guong-dong-ke-thua-nguy-tien-bao-vuong-lam","name":"Gương đồng (k��� thừa ngụy tiên bảo)","cn":"","category":"phap-bao","categoryLabel":"Ngụy tiên bảo","phamCap":"Kế thừa ngụy tiên bảo","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mặt gương đồng Vương Lâm đem rao bán; lão già áo xanh vừa nhìn đã khiếp sợ hơn cả phi kiếm và lộ rõ lòng tham.","detail":"Mặt gương đồng Vương Lâm lấy ra ném cho lão già áo xanh tại Thanh Trúc Các. Lão nhìn thoáng qua thì sắc mặt biến đổi mãnh liệt, kinh sợ hơn cả lúc nhìn phi kiếm, thất thanh gọi đó là “kế thừa ngụy tiên bảo”, trong mắt lộ rõ lòng tham. Vương Lâm ra giá năm vạn tiên ngọc — khoản tích lũy trăm năm lão dành cho việc Vấn Đỉnh.","nguon":["@c0619"]},{"id":"phi-kiem-nguy-tien-bao-vuong-lam","name":"Phi kiếm (ngụy tiên bảo)","cn":"","category":"phap-bao","categoryLabel":"Ngụy tiên bảo","phamCap":"Ngụy tiên bảo (tính dung hợp linh bảo bậc trung, linh hoạt sắc bén linh bảo bậc cao)","soHuu":["Lão già áo xanh (trưởng lão Thanh Trúc Các)"],"trangThai":"doi-ten","tenCu":"Phi kiếm tự luyện của Vương Lâm","blurb":"Thanh phi kiếm Vương Lâm tự luyện đem bán; mang lạc ấn thuấn di, thuật Đại Na Di và lôi điện kì dị, bán ba nghìn tiên ngọc.","detail":"Thanh phi kiếm Vương Lâm tự luyện và đem bán tại Thanh Trúc Các. Tính chất dung hợp linh lực đạt linh bảo bậc trung, linh hoạt sắc bén đạt linh bảo bậc cao, chỉ kém về tốc độ. Mang lạc ấn thuấn di (nhờ ý cảnh sinh tử luân hồi nuôi dưỡng nên sinh sôi không ngừng), thuật Đại Na Di và một đạo lôi điện kì dị chạm vào thì chấn người lùi mấy bước. Lão già áo xanh định danh đây là ngụy tiên bảo và mua với giá ba nghìn tiên ngọc.","nguon":["@c0619"]},{"id":"tien-ngoc-vat-lieu-tu-luyen","name":"Tiên ngọc","cn":"","category":"nguyen-lieu","categoryLabel":"Tiên tệ / vật liệu tu luyện","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật liệu tu luyện cực kỳ khan hiếm, tu sĩ từ Anh Biến trở lên tiêu hao lượng lớn mỗi ngày; tu vi Vấn Đỉnh cần lượng khổng lồ hơn Anh Biến nhiều.","detail":"Tiên ngọc là tiên tệ kiêm vật liệu tu luyện then chốt. Vương Lâm dùng nghìn khối thổ nạp ba ngày thì hóa thành bụi phấn. Hắn nhận ra tu vi Vấn Đỉnh tiêu hao tiên ngọc với số lượng khổng lồ hơn nhiều Anh Biến — kể cả thêm hai mươi vạn của Tôn Gia cũng không đủ tiến lên Vấn Đỉnh trung kỳ, còn Vấn Đỉnh hậu kỳ và viên mãn trùng kích Âm Dương Hư Thực còn cần nhiều hơn. Hắn suy tư rằng tiên giới đã không còn thì lấy đâu ra nhiều tiên ngọc, đoán tu sĩ bước thứ hai như Thiên Vận Tử có lẽ không cần tiên ngọc hoặc có phương pháp đặc biệt thay thế.","nguon":["@c0621"]},{"id":"bat-pham-thu-than-dan","name":"Bát phẩm thứ thần đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bát phẩm","soHuu":[],"trangThai":"dang-co","blurb":"Một viên đan dược bát phẩm được đem ra đấu giá tại Bảo Hợp Lâu của Nhiễm Gia bảy ngày sau, do Tôn Khải Minh nhắc tới.","detail":"Bát phẩm thứ thần đan là vật phẩm chủ chốt của cuộc đấu giá do Bảo Hợp Lâu của Nhiễm Gia tổ chức trong thành, diễn ra bảy ngày sau thời điểm Tôn Khải Minh gặp Vương Lâm. Chính vì viên đan này mà Vương Lâm nhận lệnh bài đấu giá.","nguon":["@c0621"]},{"id":"lenh-bai-dau-gia-hong-sac","name":"Lệnh bài đấu giá hồng sắc","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối lệnh bài màu hồng cho phép tham dự cuộc đấu giá ở Bảo Hợp Lâu của Nhiễm Gia, Tôn Khải Minh đưa cho Vương Lâm.","detail":"Một khối lệnh bài đấu giá hồng sắc do Tôn Khải Minh lấy ra đưa cho Vương Lâm sau khi hắn bảo mang đến. Lệnh bài cho phép tham dự cuộc đấu giá tại Bảo Hợp Lâu của Nhiễm Gia bảy ngày sau, nơi có bát phẩm thứ thần đan.","nguon":["@c0621"]},{"id":"guong-dong-nguy-tien-bao-ke-thua","name":"Gương đồng (ngụy tiên bảo kế thừa)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ngụy tiên bảo","soHuu":["Vương Lâm","Lão già áo xanh (trưởng lão Thanh Trúc Các)"],"trangThai":"doi-ten","blurb":"Ngụy tiên bảo kèm ngọc giản kế thừa, khiến tu sĩ Anh Biến cực kỳ động tâm.","detail":"Gương đồng do Vương Lâm kế thừa, là ngụy tiên bảo kèm ngọc giản kế thừa. Một lão già Anh Biến tại Thanh Trúc Các cực kỳ động tâm, cho rằng thu được vật này thì một tu sĩ Anh Biến có thể giao đấu với Anh Biến đại viên mãn. Lão xuất hơn một vạn tiên ngọc cộng toàn bộ số dư túi trữ vật để mua ngọc giản kế thừa của gương đồng. Trùng vật khởi từ gương đồng kế thừa ngụy tiên bảo của Vương Lâm.","nguon":["@c0620"]},{"id":"tram-cai-toc-nguy-tien-bao-vuong-lam","name":"Trâm cài tóc (ngụy tiên bảo)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ngụy tiên bảo","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một kiện ngụy tiên bảo khác của Vương Lâm, đưa ra nhưng lão già không hứng thú vì không phải loại kế thừa.","detail":"Cây trâm cài tóc, cũng là một ngụy tiên bảo của Vương Lâm. Hắn đưa ra cho lão già Anh Biến sau khi bán gương đồng, nhưng lão thất vọng vì chỉ muốn loại có kế thừa, rồi rời Thanh Trúc Các.","nguon":["@c0620"]},{"id":"phap-bao-dac-biet-lieu-mi","name":"Pháp bảo đặc biệt (nhằm vào Vương Lâm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Liễu Mi"],"trangThai":"dang-co","blurb":"Pháp bảo mà Liễu Mi đã chuẩn bị riêng để nhằm vào Vương Lâm, nay nàng cho rằng không còn chỗ dùng.","detail":"Một pháp bảo đặc biệt Liễu Mi từng dụng tâm chuẩn bị riêng để đối phó Vương Lâm. Khi cho rằng hắn không còn xứng là đối thủ, nàng tiếc nuối vì pháp bảo nay không còn chỗ dùng, lòng dậy tia bứt rứt đau khổ rồi bị lạnh lùng thay thế.","nguon":["@c0622"]},{"id":"la-thien-thach","name":"La Thiên Thạch","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Sư phụ của Liễu Mi"],"trangThai":"dang-co","blurb":"Vật do tổ tiên Huyễn Gia lưu lại, giúp dễ dàng vượt khoảng cách tới Thiên Huyễn Tinh trên La Thiên Tinh Vực.","detail":"Vật do tổ tiên Huyễn Gia lưu lại. Nhờ La Thiên Thạch, sư phụ Liễu Mi dễ dàng đưa nàng đến Thiên Huyễn Tinh — quê hương gia tộc — dù đã vài ngàn năm chưa quay về.","nguon":["@c0622"]},{"id":"bat-pham-than-dan-thu-than-dan","name":"Bát phẩm thần đan (thứ thần đan)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bát phẩm","soHuu":[],"trangThai":"da-dung","blurb":"Đan dược bát phẩm còn gọi thứ thần đan; Tôn Gia dùng làm mồi thăm dò Vương Lâm, với tu vi hiện tại của hắn vẫn còn hiệu quả.","detail":"Trong phân cấp đan dược (cửu phẩm = thần đan, bát phẩm = thứ thần đan, thất phẩm = tiên đan, tên do hậu nhân bịa), bát phẩm thần đan được lão già hắc y dùng làm mồi đi kèm một lệnh bài để thăm dò xem Vương Lâm có động tâm hay không. Cực phẩm đan dược là cực hạn, tới bước thứ hai sẽ vô tác dụng, nhưng với tu vi hiện nay của Vương Lâm thì bát phẩm vẫn còn hiệu quả.","nguon":["@c0622"]},{"id":"bat-pham-dan-duoc-bao-hop-lau","name":"Bát phẩm đan dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bát phẩm","soHuu":["Lão tổ Nhiễm Gia","Tôn Tích","Tiêu Diêu Cư Sĩ"],"trangThai":"dang-co","blurb":"Đan dược bát phẩm cực quý với tu sĩ Vấn Đỉnh, tổng năm viên; chỉ Vấn Đỉnh nuốt được, tu sĩ dưới Vấn Đỉnh nuốt sẽ tự bạo cơ thể mà chết.","detail":"Vật trục chính của chương: bốn năm trước được ba người Tôn Tích, lão tổ Nhiễm Gia và Tiêu Diêu Cư Sĩ cướp từ một tu sĩ ngoại lai, tổng cộng năm viên — lão tổ Nhiễm Gia đoạt ba viên, hai người còn lại mỗi người một viên. Đan dược cực quý đối với tu sĩ Vấn Đỉnh, nhưng tu sĩ dưới cảnh giới Vấn Đỉnh nuốt vào sẽ tự bạo cơ thể chết, linh dược biến thành độc dược. Tại Bảo Hợp Lâu thành Đông, đan dược được mang ra đấu giá với giá khởi điểm một vạn tiên ngọc — thực chất là mồi nhử do lão tổ Vấn Đỉnh Nhiễm Gia giăng để dụ Vương Lâm mua mà dính vào ân oán diệt tộc với Huyễn Gia.","nguon":["@c0623"]},{"id":"lenh-bai-chu-tinh-thien-huyen","name":"Lệnh bài Chủ Tinh Thiên Huyễn","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"","soHuu":["Tu sĩ ngoại lai (tộc nhân Huyễn Gia)"],"trangThai":"dang-co","blurb":"Tín vật của tộc nhân Huyễn Gia, tìm thấy trong túi trữ vật kẻ bị giết bốn năm trước; nguồn gốc mối nguy diệt tộc gắn với bát phẩm đan dược.","detail":"Lệnh bài gắn với chủ tinh Thiên Huyễn của Huyễn Gia, nằm trong túi trữ vật của tu sĩ ngoại lai bị giết bốn năm trước. Huyễn Gia ở Thiên Huyễn Tinh cực bá đạo: tộc nhân bị người ngoài giết thì mọi kẻ liên quan đều bị diệt tộc, ai động vào vật phẩm trong túi trữ vật của tộc nhân (kể cả mua được qua đấu giá) cũng bị trừng phạt; chỉ trả lại bằng hai tay mới may ra còn đường sống. Vì lệnh bài này, đến nay Tôn Tích không dám nuốt phần đan dược của mình.","nguon":["@c0623"]},{"id":"tui-tru-vat-ton-thai","name":"Túi trữ vật của Tôn Thái","category":"khac","categoryLabel":"Vật chứa","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Túi trữ vật Tôn Thái tặng Vương Lâm để tạ ơn việc đưa về quê xưa.","detail":"Bên trong chứa ít tiên ngọc — vốn Tôn Thái dành để khôi phục tu vi — cùng tâm đắc về luyện đan, luyện khí của hắn. Tôn Thái lấy ra đặt sang bên, tặng Vương Lâm coi như cảm tạ.","nguon":["@c0625"]},{"id":"van-tai-han-bang","name":"Vạn tái hàn băng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Khối băng cường đại mà một người đàn ông trung niên hấp thu hàn khí sâu trong sông băng Nhiễm Vân tinh.","detail":"Một khối băng mạnh nằm sâu trong sông băng xa trên Nhiễm Vân tinh; người đàn ông trung niên đang hấp thu hàn khí từ nó khi cảm nhận cơn lốc tiên lực của Vương Lâm.","nguon":["@c0626"]},{"id":"phap-bao-chuan-bi-lieu-mi","name":"Pháp bảo Liễu Mi chuẩn bị cho “hắn”","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Liễu Mi"],"trangThai":"dang-co","blurb":"Vật trong túi trữ vật Liễu Mi từng chuẩn bị cho một nam nhân, nay nàng than đã vô dụng.","detail":"Một vật trong túi trữ vật của Liễu Mi đột nhiên dao động; nàng cắn ngón tay nhỏ một giọt máu bắn vào trấn lại khiến dao động biến mất, rồi nhẹ than pháp bảo “chuẩn bị cho hắn” cũng không còn tác dụng.","nguon":["@c0626"]},{"id":"tien-vue-con-roi-vuong-lam-627","name":"Con rối Tiên Vệ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Con rối ẩn trong bóng của Vương Lâm, lao ra đánh tan Chưởng Tâm Lôi và huých trọng thương lão tổ Nhiễm gia.","detail":"Con rối Tiên Vệ ẩn trong bóng của Vương Lâm, khi cần thì lao ra trong nháy mắt đánh tan đòn Chưởng Tâm Lôi của lão tổ Nhiễm gia rồi huých khiến lão phun máu lui lại như lưu tinh, sau đó co rụt biến mất sau lưng Vương Lâm. Là phương tiện áp chế của hắn dưới danh “Hứa mỗ”.","nguon":["@c0627"]},{"id":"cay-luoc-den-muoi-chin-rang","name":"Cây lược đen (lược mười chín răng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ngụy tiên bảo (loại công kích)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Cây lược đen mười chín răng tản hương máu tanh, khí thế hung ác.","detail":"Một cây lược màu đen, mười chín răng lược, tản ra hương vị máu tanh, khí thế hung ác. Vương Lâm nhận ra đây là ngụy tiên bảo loại công kích, trên có pháp trận uy lực không tầm thường; vẫn còn sót oán niệm của người Huyễn gia chết năm đó, là di vật được lão tổ Nhiễm gia và Tiêu Dao tán nhân đoạt được rồi đưa cho Vương Lâm.","nguon":["@c0628"]},{"id":"doi-da-danh-lua-tu-kim","name":"Đôi đá đánh lửa tử kim (đá lửa)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Pháp bảo thiên nhiên hình thành / tài liệu luyện khí","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đôi đá lửa tử kim ma sát phát ra kim hỏa, là tài liệu luyện khí thiên nhiên.","detail":"Đôi đá đánh lửa màu tử kim, cọ xát phát ra đốm lửa như sao và hơi nóng. Nhờ trí nhớ Cổ Thần Đồ Ti, Vương Lâm hiểu đây là pháp bảo do thiên nhiên tạo thành: vốn là kim loại độ cứng rất cao, ẩn chứa thần thông kỳ dị nên ma sát phát ra kim hỏa, hiệu quả giống dương hỏa mà Tổng quản Thiên Yêu quận từng thi triển ở vùng đất Yêu Linh năm xưa. Trong mắt Cổ Thần, đá lửa kỳ thật là một loại tài liệu luyện khí. Khuyết điểm: tính kim loại ẩn chứa quá ít; nếu nhiều hơn uy lực không kém ngụy tiên bảo cao nhất, lớn hơn chút có thể sánh tiên bảo cấp thấp. Đôi này tạp chất nhiều, luyện hóa sợ không đạt một phần mười.","nguon":["@c0628"]},{"id":"lenh-bai-than-phan-nguoi-huyen-gia","name":"Lệnh bài thân phận người Huyễn gia","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Vật phẩm (chất liệu tầm thường)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lệnh bài thân phận ẩn một thần thông nhỏ liên quan mệnh hồn.","detail":"Lệnh bài thoạt nhìn chỉ biểu thị thân phận, chất liệu tầm thường, nhưng Vương Lâm cảm thấy cổ quái. Hắn triệu Tiên Vệ bao phủ lệnh bài, theo biến hóa âm dương hư thực mà nhìn ra bên trong có một thần thông nhỏ liên quan tới mệnh hồn — báo cho Huyễn gia biết chủ lệnh bài đã chết.","nguon":["@c0628"]},{"id":"ngoc-gian-nguoi-huyen-gia","name":"Ngọc giản (của người Huyễn gia)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Ngọc giản","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản ghi Thiên Huyễn Vô Tình đạo và tin tức mỏ Kim Viêm Vân Hà tinh.","detail":"Ngọc giản chỉ còn một tia oán niệm người chủ; ba lão tổ Nhiễm gia kiêng kỵ không dám dò thần thức. Vương Lâm cho thần thức dung nhập, tia oán niệm tan, ngọc giản phát một đạo dao động (sóng đưa tin) sắp tràn ra ngoài phòng, bị Vương Lâm dùng điện quang trong mắt đánh nát. Nội dung: ghi chép Thiên Huyễn Vô Tình đạo (cấm chế phá bằng huyết mạch) và tin tức người Huyễn gia chết bốn năm trước ghi lại — ở Vân Hà tinh phát hiện một mỏ quáng Kim Viêm.","nguon":["@c0628"]},{"id":"kim-kiem-huyen-dong","name":"Kim kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Huyễn Đông"],"trangThai":"hong","blurb":"Phi kiếm Huyễn Đông lấy từ túi trữ vật, kích Uy lực của Kim để chống Tịch Diệt chỉ rồi vỡ vụn tiêu tan.","detail":"Phi kiếm Huyễn Đông vỗ túi trữ vật lấy ra, bấm pháp quyết kích Uy lực của Kim để chống đỡ chỉ phong Tịch Diệt chỉ của Vương Lâm; kim kiếm va vào chỉ phong rồi vỡ vụn tiêu tan.","nguon":["@c0629"]},{"id":"tinh-la-ban-huyen-dong","name":"Tinh la bàn (Huyễn Đông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Huyễn Đông"],"trangThai":"dang-co","blurb":"Pháp bảo bay liên tinh; Huyễn Đông đạp tinh la bàn gào thét lao đến Nhiễm Vân tinh.","detail":"Pháp bảo di chuyển giữa các tinh cầu. Huyễn Đông đạp tinh la bàn lao tới Nhiễm Vân tinh từ ngoài không gian, tốc độ cực nhanh.","nguon":["@c0629"]},{"id":"ngan-huyet-phu-huyen-gia","name":"Một ngàn huyết phù","category":"khac","categoryLabel":"Phù lục","phamCap":"Phù khắc huyết mạch","soHuu":["Lão tổ Huyễn Gia","Liễu Mi"],"trangThai":"da-dung","blurb":"Một ngàn huyết phù luyện từ máu mấy vạn tộc nhân Huyễn gia, khắc lên thân Liễu Mi rồi dung nhập thành huyết mạch.","detail":"Lão tổ Huyễn gia dung hợp máu mấy vạn tộc nhân thành một, luyện hóa huyết mạch tinh khiết thành một ngàn huyết phù. Trong Hoán huyết đại pháp, ao máu sụp đổ khiến huyết phù khắc lên thân Liễu Mi, trán nàng nứt phun máu, rồi dung nhập thành huyết mạch Huyễn gia.","nguon":["@c0631"]},{"id":"mo-quang-kim-viem-632","name":"Mỏ quáng Kim Viêm","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng vật / Xương cốt","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Mỏ phát ánh sáng vàng kéo dài vô số dặm trong lòng Vân Hà tinh, kỳ thực là xương cốt của con Vọng Nguyệt khổng lồ.","detail":"Mỏ quáng Kim Viêm nằm ở chỗ sâu nhất tầng ngầm Vân Hà tinh, một đoạn chui lên mặt khác của tinh cầu. Mỏ lộ rõ không che giấu nhưng không ai khai thác. Vương Lâm nhận ra nó chỉnh tề bất thường, lớn nhỏ thô mịn từ đầu đến cuối khá giống nhau, giống một bộ xương dài — kỳ thực là xương cốt của con Vọng Nguyệt khổng lồ chính là Vân Hà tinh. Thu mỏ trực tiếp sẽ kích thích Vọng Nguyệt thức tỉnh. Năm xưa người Huyễn gia chỉ khôn khéo nhặt một ít ở mặt khác tinh cầu rồi rời đi.","nguon":["@c0632"]},{"id":"doa-hoa-hong-do-hong-diep","name":"Đóa hoa hồng màu đỏ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Liễu Mi"],"trangThai":"da-dung","blurb":"Pháp bảo của Hồng Điệp; cánh hoa bay lên mang lực lượng kỳ dị tấn công, nhụy hoa hợp thành phù văn.","detail":"Khi Liễu Mi hóa thành Hồng Điệp, nàng lấy ra đóa hoa hồng màu đỏ. Cánh hoa vung lên mang lực lượng kỳ dị tấn công Vương Lâm; nhụy hoa lại tổ hợp thành phù văn lớn trăm trượng. Bị Thất Tinh kiếm trận và Đạo hóa Hoàng Tuyền của Vương Lâm phá tan.","nguon":["@c0634"]},{"id":"suong-den-oan-khi-lieu-mi","name":"Sương đen oán khí","cn":"","aliases":["Hắc mang"],"category":"khac","categoryLabel":"Vật phẩm / Độc","phamCap":"","soHuu":["Liễu Mi"],"trangThai":"da-dung","blurb":"Đ���o sương đen trong túi trữ vật Liễu Mi, thả ra oán khí kinh thiên phủ mười dặm như quỷ cảnh.","detail":"Liễu Mi mở túi trữ vật thả ra một đạo sương đen kèm oán khí kinh thiên tràn ngập mười dặm như quỷ cảnh. Hắc mang tốc độ cực nhanh lướt qua Tiên vệ khôi lỗi xông thẳng tới Vương Lâm; khi bị cuồng phong thổi tan, lộ ra một đôi mắt đen đục ngầu vô thần chỉ chứa oán diễm khiến Vương Lâm sững lại.","nguon":["@c0634"]},{"id":"doa-hoa-hong-mau-lam-608","name":"Đóa hoa hồng màu lam","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đóa hoa hồng màu lam xuất hiện trong tay Vương Lâm khi dọn túi trữ vật; nhìn vào hiện ra thân ảnh đỏ như lửa.","detail":"Khi Vương Lâm đang dọn dẹp túi trữ vật để luyện hóa pháp bảo cũ thành vật liệu, một đóa hoa hồng màu lam bất chợt hiện ra trong tay. Nhìn đóa hoa, trước mắt Vương Lâm hiện ra một thân ảnh đỏ như lửa, khiến hắn do dự rồi thu hồi đóa hoa, không đưa vào luyện hóa. Gắn với ký ức/người liên quan, để ngỏ.","nguon":["@c0608"]},{"id":"tieu-cau-anh-sang-diu-dang-610","name":"Tiểu cầu phát ánh sáng dịu dàng","category":"khac","categoryLabel":"Vật phẩm thần bí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Quả cầu nhỏ tỏa sáng dịu dàng dung nhập vào tay Vương Lâm ngay trước khi cuộn tranh nữ tử xuất hiện.","detail":"Một tiểu cầu phát ánh sáng dịu dàng nằm trong lòng bàn tay Vương Lâm, dung nhập vào tay hắn ngay trước khoảnh khắc cuộn tranh nữ tử tự bay ra và hiện thân ảnh gọi “Đi xuống”. Liên hệ chưa rõ với bức tranh và đáy hố sâu.","nguon":["@c0610"]},{"id":"con-roi-tien-ve-phong-an-612","name":"Con rối Tiên Vệ (phong ấn bức tranh)","category":"phap-bao","categoryLabel":"Con rối","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Con rối Tiên Vệ Vương Lâm triệu ra từ hư vô để đánh thêm đạo phong ấn mênh mông, đảm bảo phong ấn bức tranh nữ tử triệt để.","detail":"Sau khi phong ấn bức tranh, Vương Lâm ẩn ở xa chờ. Khi chỗ phong ấn nứt ra ba động yếu ớt do nữ tử cố thoát, hắn triệu con rối Tiên Vệ, hai tay con rối bắt quyết đánh ra đạo phong ấn mênh mông đè lên ba động, kèm một tiếng hừ thảm. Lần xuất hiện sau của ba động cũng bị phong ấn hoàn toàn triệt để.","nguon":["@c0612"]},{"id":"la-yeu-thach-truyen-tong-612","name":"La Yêu thạch (khởi động truyền tống trận cổ)","category":"nguyen-lieu","categoryLabel":"Khoáng thạch","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Khoáng thạch là điều kiện duy nhất để khởi động truyền tống trận cổ về La Thiên tinh vực; tiên ngọc cũng vô dụng.","detail":"Dưới tảng đá che truyền tống trận cổ ở đáy hố có một truyền tống trận chỉ khởi động được nếu có La Yêu thạch — ngay cả tiên ngọc cũng không thay thế được. Vương Lâm phá hủy tảng đá che trận rồi không sử dụng, mà phong ấn bức tranh.","nguon":["@c0612"]}]};
